window.BILARA = window.BILARA || {};
window.BILARA["dn14"] = window.BILARA["dn14"] || {};
window.BILARA["dn14"]["vi"] = {
  "dn14:0.1": "Trường Bộ Kinh 14 ",
  "dn14:0.2": "Kinh Đại Bổn ",
  "dn14:1.0": "1. Câu chuyện liên hệ đến các đời sống quá khứ ",
  "dn14:1.1.1": "Tôi nghe như vầy—",
  "dn14:1.1.2": "Một thời, Thế Tôn trú tại Sāvatthī, trong Jetavana, khu vườn của ông Anāthapiṇḍika, tại am Kareri. ",
  "dn14:1.1.3": "Lúc bấy giờ, nhiều vị tỳ-kheo sau bữa ăn, đi khất thực trở về, đang ngồi tụ họp tại giảng đường tròn Kareri, thì một cuộc pháp thoại liên hệ đến các đời sống quá khứ được khởi lên: ",
  "dn14:1.1.4": "“Như thế này là đời sống quá khứ, như thế kia là đời sống quá khứ.” ",
  "dn14:1.2.1": "Thế Tôn với thiên nhĩ thanh tịnh, siêu nhân, đã nghe được câu chuyện đàm luận ấy của các vị tỳ-kheo. ",
  "dn14:1.2.2": "Rồi Thế Tôn từ chỗ ngồi đứng dậy, đi đến giảng đường tròn Kareri; đến nơi, Ngài ngồi xuống chỗ đã soạn sẵn, rồi bảo các tỳ-kheo: ",
  "dn14:1.2.3": "“Này các tỳ-kheo, hiện giờ các ông đang ngồi bàn luận câu chuyện gì? Và câu chuyện gì của các ông đang bị bỏ dở giữa chừng?” ",
  "dn14:1.2.4": "Khi được nói vậy, các tỳ-kheo bạch Thế Tôn: ",
  "dn14:1.2.5": "“Bạch Thế Tôn, ở đây chúng con sau bữa ăn, đi khất thực trở về, đang ngồi tụ họp tại giảng đường tròn Kareri, thì một cuộc pháp thoại liên hệ đến các đời sống quá khứ được khởi lên: ",
  "dn14:1.2.6": "‘Như thế này là đời sống quá khứ, như thế kia là đời sống quá khứ.’ ",
  "dn14:1.2.7": "Bạch Thế Tôn, đó là câu chuyện của chúng con đang bỏ dở giữa chừng. Rồi Thế Tôn đã đến.”",
  "dn14:1.3.1": "“Này các tỳ-kheo, các ông có muốn nghe một pháp thoại liên hệ đến các đời sống quá khứ chăng?” ",
  "dn14:1.3.2": "“Bạch Thế Tôn, nay là thời; bạch Thiện Thệ, nay là thời; ",
  "dn14:1.3.3": "nếu Thế Tôn thuyết một pháp thoại liên hệ đến các đời sống quá khứ, sau khi nghe Thế Tôn, các tỳ-kheo sẽ ghi nhớ.” ",
  "dn14:1.3.4": "“Vậy thì, này các tỳ-kheo, hãy lắng nghe, khéo tác ý, Ta sẽ nói.” ",
  "dn14:1.3.5": "“Vâng, bạch Thế Tôn,” các tỳ-kheo vâng đáp Thế Tôn. ",
  "dn14:1.3.6": "Thế Tôn nói như sau: ",
  "dn14:1.4.1": "“Này các tỳ-kheo, cách đây chín mươi mốt kiếp, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã xuất hiện ở đời. ",
  "dn14:1.4.2": "Này các tỳ-kheo, cách đây ba mươi mốt kiếp, đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, đã xuất hiện ở đời. ",
  "dn14:1.4.3": "Cũng chính trong kiếp ba mươi mốt ấy, này các tỳ-kheo, đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, đã xuất hiện ở đời. ",
  "dn14:1.4.4": "Cũng chính trong hiền kiếp này, này các tỳ-kheo, đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, đã xuất hiện ở đời. ",
  "dn14:1.4.5": "Cũng chính trong hiền kiếp này, này các tỳ-kheo, đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, đã xuất hiện ở đời. ",
  "dn14:1.4.6": "Cũng chính trong hiền kiếp này, này các tỳ-kheo, đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, đã xuất hiện ở đời. ",
  "dn14:1.4.7": "Cũng chính trong hiền kiếp này, này các tỳ-kheo, nay Ta là bậc A-la-hán, Chánh Đẳng Giác, đã xuất hiện ở đời. ",
  "dn14:1.5.1": "Này các tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, thuộc giai cấp sát-đế-lỵ, sinh trong dòng họ sát-đế-lỵ. ",
  "dn14:1.5.2": "Này các tỳ-kheo, đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, thuộc giai cấp sát-đế-lỵ, sinh trong dòng họ sát-đế-lỵ. ",
  "dn14:1.5.3": "Này các tỳ-kheo, đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, thuộc giai cấp sát-đế-lỵ, sinh trong dòng họ sát-đế-lỵ. ",
  "dn14:1.5.4": "Này các tỳ-kheo, đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, thuộc giai cấp bà-la-môn, sinh trong dòng họ bà-la-môn. ",
  "dn14:1.5.5": "Này các tỳ-kheo, đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, thuộc giai cấp bà-la-môn, sinh trong dòng họ bà-la-môn. ",
  "dn14:1.5.6": "Này các tỳ-kheo, đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, thuộc giai cấp bà-la-môn, sinh trong dòng họ bà-la-môn. ",
  "dn14:1.5.7": "Này các tỳ-kheo, nay Ta là bậc A-la-hán, Chánh Đẳng Giác, thuộc giai cấp sát-đế-lỵ, sinh trong dòng họ sát-đế-lỵ. ",
  "dn14:1.6.1": "Này các tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, thuộc họ Koṇḍañña. ",
  "dn14:1.6.2": "Này các tỳ-kheo, đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, thuộc họ Koṇḍañña. ",
  "dn14:1.6.3": "Này các tỳ-kheo, đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, thuộc họ Koṇḍañña. ",
  "dn14:1.6.4": "Này các tỳ-kheo, đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, thuộc họ Kassapa. ",
  "dn14:1.6.5": "Này các tỳ-kheo, đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, thuộc họ Kassapa. ",
  "dn14:1.6.6": "Này các tỳ-kheo, đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, thuộc họ Kassapa. ",
  "dn14:1.6.7": "Này các tỳ-kheo, nay Ta là bậc A-la-hán, Chánh Đẳng Giác, thuộc họ Gotama. ",
  "dn14:1.7.1": "Này các tỳ-kheo, tuổi thọ của đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, là tám mươi nghìn năm. ",
  "dn14:1.7.2": "Này các tỳ-kheo, tuổi thọ của đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, là bảy mươi nghìn năm. ",
  "dn14:1.7.3": "Này các tỳ-kheo, tuổi thọ của đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, là sáu mươi nghìn năm. ",
  "dn14:1.7.4": "Này các tỳ-kheo, tuổi thọ của đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, là bốn mươi nghìn năm. ",
  "dn14:1.7.5": "Này các tỳ-kheo, tuổi thọ của đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, là ba mươi nghìn năm. ",
  "dn14:1.7.6": "Này các tỳ-kheo, tuổi thọ của đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, là hai mươi nghìn năm. ",
  "dn14:1.7.7": "Này các tỳ-kheo, tuổi thọ của Ta hiện nay ít ỏi, ngắn ngủi, nhỏ bé; ai sống lâu thì được một trăm năm hoặc hơn chút ít. ",
  "dn14:1.8.1": "Này các tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã giác ngộ dưới gốc cây pāṭali. ",
  "dn14:1.8.2": "Này các tỳ-kheo, đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, đã giác ngộ dưới gốc cây puṇḍarīka. ",
  "dn14:1.8.3": "Này các tỳ-kheo, đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, đã giác ngộ dưới gốc cây sāla. ",
  "dn14:1.8.4": "Này các tỳ-kheo, đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, đã giác ngộ dưới gốc cây sirīsa. ",
  "dn14:1.8.5": "Này các tỳ-kheo, đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, đã giác ngộ dưới gốc cây udumbara. ",
  "dn14:1.8.6": "Này các tỳ-kheo, đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, đã giác ngộ dưới gốc cây nigrodha. ",
  "dn14:1.8.7": "Này các tỳ-kheo, nay Ta là bậc A-la-hán, Chánh Đẳng Giác, đã giác ngộ dưới gốc cây assattha. ",
  "dn14:1.9.1": "Này các tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, có đôi đệ tử tên là Khaṇḍa và Tissa, là đôi tối thắng, đôi tốt lành. ",
  "dn14:1.9.2": "Này các tỳ-kheo, đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, có đôi đệ tử tên là Abhibhū và Sambhava, là đôi tối thắng, đôi tốt lành. ",
  "dn14:1.9.3": "Này các tỳ-kheo, đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, có đôi đệ tử tên là Soṇa và Uttara, là đôi tối thắng, đôi tốt lành. ",
  "dn14:1.9.4": "Này các tỳ-kheo, đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, có đôi đệ tử tên là Vidhura và Sañjīva, là đôi tối thắng, đôi tốt lành. ",
  "dn14:1.9.5": "Này các tỳ-kheo, đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, có đôi đệ tử tên là Bhiyyosa và Uttara, là đôi tối thắng, đôi tốt lành. ",
  "dn14:1.9.6": "Này các tỳ-kheo, đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, có đôi đệ tử tên là Tissa và Bhāradvāja, là đôi tối thắng, đôi tốt lành. ",
  "dn14:1.9.7": "Này các tỳ-kheo, nay Ta có đôi đệ tử tên là Sāriputta và Moggallāna, là đôi tối thắng, đôi tốt lành. ",
  "dn14:1.10.1": "Này các tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, có ba hội chúng đệ tử. Một hội chúng đệ tử gồm sáu mươi tám vạn tỳ-kheo, một hội chúng đệ tử gồm một trăm nghìn tỳ-kheo, một hội chúng đệ tử gồm tám mươi nghìn tỳ-kheo. Này các tỳ-kheo, đó là ba hội chúng đệ tử của đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là các vị lậu tận. ",
  "dn14:1.10.2": "Này các tỳ-kheo, đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, có ba hội chúng đệ tử. Một hội chúng đệ tử gồm một trăm nghìn tỳ-kheo, một hội chúng đệ tử gồm tám mươi nghìn tỳ-kheo, một hội chúng đệ tử gồm bảy mươi nghìn tỳ-kheo. Này các tỳ-kheo, đó là ba hội chúng đệ tử của đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là các vị lậu tận. ",
  "dn14:1.10.3": "Này các tỳ-kheo, đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, có ba hội chúng đệ tử. Một hội chúng đệ tử gồm tám mươi nghìn tỳ-kheo, một hội chúng đệ tử gồm bảy mươi nghìn tỳ-kheo, một hội chúng đệ tử gồm sáu mươi nghìn tỳ-kheo. Này các tỳ-kheo, đó là ba hội chúng đệ tử của đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là các vị lậu tận. ",
  "dn14:1.10.4": "Này các tỳ-kheo, đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, có một hội chúng đệ tử gồm bốn mươi nghìn tỳ-kheo. Này các tỳ-kheo, đó là một hội chúng đệ tử của đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là các vị lậu tận. ",
  "dn14:1.10.5": "Này các tỳ-kheo, đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, có một hội chúng đệ tử gồm ba mươi nghìn tỳ-kheo. Này các tỳ-kheo, đó là một hội chúng đệ tử của đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là các vị lậu tận. ",
  "dn14:1.10.6": "Này các tỳ-kheo, đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, có một hội chúng đệ tử gồm hai mươi nghìn tỳ-kheo. Này các tỳ-kheo, đó là một hội chúng đệ tử của đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là các vị lậu tận. ",
  "dn14:1.10.7": "Này các tỳ-kheo, nay Ta có một hội chúng đệ tử gồm một nghìn hai trăm năm mươi tỳ-kheo. Này các tỳ-kheo, đó là một hội chúng đệ tử của Ta, tất cả đều là các vị lậu tận. ",
  "dn14:1.11.1": "Này các tỳ-kheo, vị tỳ-kheo thị giả của đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, tên là Asoka, là thị giả bậc nhất. ",
  "dn14:1.11.2": "Này các tỳ-kheo, vị tỳ-kheo thị giả của đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, tên là Khemaṅkara, là thị giả bậc nhất. ",
  "dn14:1.11.3": "Này các tỳ-kheo, vị tỳ-kheo thị giả của đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, tên là Upasanta, là thị giả bậc nhất. ",
  "dn14:1.11.4": "Này các tỳ-kheo, vị tỳ-kheo thị giả của đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, tên là Buddhija, là thị giả bậc nhất. ",
  "dn14:1.11.5": "Này các tỳ-kheo, vị tỳ-kheo thị giả của đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, tên là Sotthija, là thị giả bậc nhất. ",
  "dn14:1.11.6": "Này các tỳ-kheo, vị tỳ-kheo thị giả của đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, tên là Sabbamitta, là thị giả bậc nhất. ",
  "dn14:1.11.7": "Này các tỳ-kheo, nay vị tỳ-kheo thị giả của Ta tên là Ānanda, là thị giả bậc nhất. ",
  "dn14:1.12.1": "Này các tỳ-kheo, cha của đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, là vua Bandhumā. ",
  "dn14:1.12.2": "Mẹ, người sinh ra ngài, là hoàng hậu Bandhumatī. ",
  "dn14:1.12.3": "Kinh đô của vua Bandhuma là thành Bandhumatī. ",
  "dn14:1.12.4": "Này các tỳ-kheo, cha của đức Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, là vua Aruṇa. ",
  "dn14:1.12.5": "Mẹ, người sinh ra ngài, là hoàng hậu Pabhāvatī. ",
  "dn14:1.12.6": "Kinh đô của vua Aruṇa là thành Aruṇavatī. ",
  "dn14:1.12.7": "Này các tỳ-kheo, cha của đức Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, là vua Suppatita. ",
  "dn14:1.12.8": "Mẹ, người sinh ra ngài, là hoàng hậu Vassavatī. ",
  "dn14:1.12.9": "Kinh đô của vua Suppatita là thành Anoma. ",
  "dn14:1.12.10": "Này các tỳ-kheo, cha của đức Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, là bà-la-môn Aggidatta. ",
  "dn14:1.12.11": "Mẹ, người sinh ra ngài, là nữ bà-la-môn Visākhā. ",
  "dn14:1.12.12": "Nhưng vào thời ấy, này các tỳ-kheo, có vua tên là Khema. ",
  "dn14:1.12.13": "Kinh đô của vua Khema là thành Khemavatī. ",
  "dn14:1.12.14": "Này các tỳ-kheo, cha của đức Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, là bà-la-môn Yaññadatta. ",
  "dn14:1.12.15": "Mẹ, người sinh ra ngài, là nữ bà-la-môn Uttarā. ",
  "dn14:1.12.16": "Nhưng vào thời ấy, này các tỳ-kheo, có vua tên là Sobha. ",
  "dn14:1.12.17": "Kinh đô của vua Sobha là thành Sobhavatī. ",
  "dn14:1.12.18": "Này các tỳ-kheo, cha của đức Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, là bà-la-môn Brahmadatta. ",
  "dn14:1.12.19": "Mẹ, người sinh ra ngài, là nữ bà-la-môn Dhanavatī. ",
  "dn14:1.12.20": "Nhưng vào thời ấy, này các tỳ-kheo, có vua tên là Kikī. ",
  "dn14:1.12.21": "Kinh đô của vua Kikī là thành Bārāṇasī. ",
  "dn14:1.12.22": "Này các tỳ-kheo, nay cha của Ta là vua Suddhodana. ",
  "dn14:1.12.23": "Mẹ, người sinh ra Ta, là hoàng hậu Māyā. ",
  "dn14:1.12.24": "Kinh đô là thành Kapilavatthu.”",
  "dn14:1.12.25": "Thế Tôn đã nói như vậy.",
  "dn14:1.12.26": "Nói xong, bậc Thiện Thệ từ chỗ ngồi đứng dậy và đi vào tịnh thất.",
  "dn14:1.13.1": "Bấy giờ, sau khi Thế Tôn vừa đi không bao lâu, giữa các vị tỳ-kheo khởi lên câu chuyện này:",
  "dn14:1.13.2": "“Thật kỳ diệu, này hiền giả, thật hy hữu, này hiền giả, là đại thần lực, đại oai lực của Như Lai.",
  "dn14:1.13.3": "Thật vậy, Như Lai có thể nhớ lại các vị Phật trong quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận cùng vòng quay, đã vượt qua mọi khổ đau: nhớ cả về dòng sinh, nhớ cả về tên gọi, nhớ cả về họ tộc, nhớ cả về thọ lượng, nhớ cả về đôi đệ tử, nhớ cả về hội chúng đệ tử:",
  "dn14:1.13.4": "‘Các đức Thế Tôn ấy đã là như vậy về dòng sinh, như vậy về tên gọi, như vậy về họ tộc, như vậy về giới hạnh, như vậy về pháp, như vậy về trí tuệ, như vậy về an trú, như vậy về giải thoát.’”",
  "dn14:1.13.5": "“Không biết có phải chính giới pháp tánh này đã được Như Lai khéo thấu triệt, nhờ khéo thấu triệt giới pháp tánh ấy mà Như Lai nhớ lại các vị Phật trong quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận cùng vòng quay, đã vượt qua mọi khổ đau: nhớ cả về dòng sinh, nhớ cả về tên gọi, nhớ cả về họ tộc, nhớ cả về thọ lượng, nhớ cả về đôi đệ tử, nhớ cả về hội chúng đệ tử: ‘Các đức Thế Tôn ấy đã là như vậy về dòng sinh, như vậy về tên gọi, như vậy về họ tộc, như vậy về giới hạnh, như vậy về pháp, như vậy về trí tuệ, như vậy về an trú, như vậy về giải thoát’;",
  "dn14:1.13.6": "hay là chư thiên đã báo cho Như Lai điều ấy, nhờ đó Như Lai nhớ lại các vị Phật trong quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận cùng vòng quay, đã vượt qua mọi khổ đau: nhớ cả về dòng sinh, nhớ cả về tên gọi, nhớ cả về họ tộc, nhớ cả về thọ lượng, nhớ cả về đôi đệ tử, nhớ cả về hội chúng đệ tử: ‘Các đức Thế Tôn ấy đã là như vậy về dòng sinh, như vậy về tên gọi, như vậy về họ tộc, như vậy về giới hạnh, như vậy về pháp, như vậy về trí tuệ, như vậy về an trú, như vậy về giải thoát.’”",
  "dn14:1.13.7": "Và câu chuyện giữa các vị tỳ-kheo ấy đang còn dang dở.",
  "dn14:1.14.1": "Bấy giờ, vào buổi chiều, Thế Tôn từ chỗ tĩnh cư đi ra, đi đến giảng đường Karerimaṇḍala; đến nơi, Ngài ngồi xuống chỗ đã soạn sẵn.",
  "dn14:1.14.2": "Ngồi xuống rồi, Thế Tôn gọi các tỳ-kheo:",
  "dn14:1.14.3": "“Này các tỳ-kheo, hiện nay các ông đang ngồi bàn luận chuyện gì? Và câu chuyện gì của các ông đang còn dang dở?”",
  "dn14:1.14.4": "Khi được nói vậy, các vị tỳ-kheo bạch Thế Tôn:",
  "dn14:1.14.5": "“Bạch Thế Tôn, ở đây, sau khi Thế Tôn vừa đi không bao lâu, giữa chúng con khởi lên câu chuyện này:",
  "dn14:1.14.6": "‘Thật kỳ diệu, này hiền giả, thật hy hữu, này hiền giả, là đại thần lực, đại oai lực của Như Lai.",
  "dn14:1.14.7": "Thật vậy, Như Lai có thể nhớ lại các vị Phật trong quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận cùng vòng quay, đã vượt qua mọi khổ đau: nhớ cả về dòng sinh, nhớ cả về tên gọi, nhớ cả về họ tộc, nhớ cả về thọ lượng, nhớ cả về đôi đệ tử, nhớ cả về hội chúng đệ tử:",
  "dn14:1.14.8": "“Các đức Thế Tôn ấy đã là như vậy về dòng sinh, như vậy về tên gọi, như vậy về họ tộc, như vậy về giới hạnh, như vậy về pháp, như vậy về trí tuệ, như vậy về an trú, như vậy về giải thoát.”",
  "dn14:1.14.9": "Không biết có phải chính giới pháp tánh này đã được Như Lai khéo thấu triệt, nhờ khéo thấu triệt giới pháp tánh ấy mà Như Lai nhớ lại các vị Phật trong quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận cùng vòng quay, đã vượt qua mọi khổ đau: nhớ cả về dòng sinh, nhớ cả về tên gọi, nhớ cả về họ tộc, nhớ cả về thọ lượng, nhớ cả về đôi đệ tử, nhớ cả về hội chúng đệ tử:",
  "dn14:1.14.10": "“Các đức Thế Tôn ấy đã là như vậy về dòng sinh, như vậy về tên gọi, như vậy về họ tộc, như vậy về giới hạnh, như vậy về pháp, như vậy về trí tuệ, như vậy về an trú, như vậy về giải thoát.”",
  "dn14:1.14.11": "Hay là chư thiên đã báo cho Như Lai điều ấy, nhờ đó Như Lai nhớ lại các vị Phật trong quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận cùng vòng quay, đã vượt qua mọi khổ đau: nhớ cả về dòng sinh, nhớ cả về tên gọi, nhớ cả về họ tộc, nhớ cả về thọ lượng, nhớ cả về đôi đệ tử, nhớ cả về hội chúng đệ tử:",
  "dn14:1.14.12": "“Các đức Thế Tôn ấy đã là như vậy về dòng sinh, như vậy về tên gọi, như vậy về họ tộc, như vậy về giới hạnh, như vậy về pháp, như vậy về trí tuệ, như vậy về an trú, như vậy về giải thoát.”’?",
  "dn14:1.14.13": "Bạch Thế Tôn, đó là câu chuyện của chúng con đang còn dang dở, thì Thế Tôn đến.”",
  "dn14:1.15.1": "“Này các tỳ-kheo, chính giới pháp tánh ấy đã được Như Lai khéo thấu triệt, nhờ khéo thấu triệt giới pháp tánh ấy mà Như Lai nhớ lại các vị Phật trong quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận cùng vòng quay, đã vượt qua mọi khổ đau: nhớ cả về dòng sinh, nhớ cả về tên gọi, nhớ cả về họ tộc, nhớ cả về thọ lượng, nhớ cả về đôi đệ tử, nhớ cả về hội chúng đệ tử:",
  "dn14:1.15.2": "‘Các đức Thế Tôn ấy đã là như vậy về dòng sinh, như vậy về tên gọi, như vậy về họ tộc, như vậy về giới hạnh, như vậy về pháp, như vậy về trí tuệ, như vậy về an trú, như vậy về giải thoát.’",
  "dn14:1.15.3": "Chư thiên cũng đã báo cho Như Lai điều ấy, nhờ đó Như Lai nhớ lại các vị Phật trong quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận cùng vòng quay, đã vượt qua mọi khổ đau: nhớ cả về dòng sinh, nhớ cả về tên gọi, nhớ cả về họ tộc, nhớ cả về thọ lượng, nhớ cả về đôi đệ tử, nhớ cả về hội chúng đệ tử:",
  "dn14:1.15.4": "‘Các đức Thế Tôn ấy đã là như vậy về dòng sinh, như vậy về tên gọi, như vậy về họ tộc, như vậy về giới hạnh, như vậy về pháp, như vậy về trí tuệ, như vậy về an trú, như vậy về giải thoát.’",
  "dn14:1.15.5": "Này các tỳ-kheo, các ông có muốn nghe thêm nữa bài pháp thoại liên hệ đến các đời sống trước chăng?”",
  "dn14:1.15.6": "“Bạch Thế Tôn, nay là thời; bạch Thiện Thệ, nay là thời;",
  "dn14:1.15.7": "mong Thế Tôn thuyết thêm bài pháp thoại liên hệ đến các đời sống trước; nghe Thế Tôn xong, các tỳ-kheo sẽ thọ trì.”",
  "dn14:1.15.8": "“Vậy thì, này các tỳ-kheo, hãy lắng nghe, khéo tác ý, Ta sẽ nói.”",
  "dn14:1.15.9": "“Vâng, bạch Thế Tôn,” các tỳ-kheo ấy vâng đáp Thế Tôn.",
  "dn14:1.15.10": "Thế Tôn nói như sau:",
  "dn14:1.16.1": "“Này các tỳ-kheo, cách nay chín mươi mốt kiếp, đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, xuất hiện ở đời.",
  "dn14:1.16.2": "Này các tỳ-kheo, đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, thuộc dòng sát-đế-lỵ, sinh ra trong gia tộc sát-đế-lỵ.",
  "dn14:1.16.3": "Này các tỳ-kheo, đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, thuộc họ Koṇḍañña.",
  "dn14:1.16.4": "Này các tỳ-kheo, đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, có thọ lượng tám mươi ngàn năm.",
  "dn14:1.16.5": "Này các tỳ-kheo, đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, thành đạo dưới gốc cây pāṭali.",
  "dn14:1.16.6": "Này các tỳ-kheo, đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, có đôi đệ tử tên là Khaṇḍa và Tissa, là đôi đệ tử thù thắng bậc nhất.",
  "dn14:1.16.7": "Này các tỳ-kheo, đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, có ba hội chúng đệ tử.",
  "dn14:1.16.8": "Một hội chúng đệ tử có sáu trăm tám mươi ngàn tỳ-kheo, một hội chúng đệ tử có một trăm ngàn tỳ-kheo, một hội chúng đệ tử có tám mươi ngàn tỳ-kheo.",
  "dn14:1.16.9": "Này các tỳ-kheo, ba hội chúng đệ tử ấy của đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là những vị đã tận lậu hoặc.",
  "dn14:1.16.10": "Này các tỳ-kheo, đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, có vị thị giả tên là Asoka, là vị thị giả bậc nhất.",
  "dn14:1.16.11": "Này các tỳ-kheo, đức Thế Tôn Tỳ-bà-thi, bậc A-la-hán, Chánh Đẳng Giác, có phụ thân là vua Bandhumā.",
  "dn14:1.16.12": "Mẫu thân, người sinh ra Ngài, là hoàng hậu tên Bandhumatī.",
  "dn14:1.16.13": "Kinh đô của vua Bandhuma là thành Bandhumatī.",
  "dn14:1.17.0": "2. Pháp tánh của Bồ-tát",
  "dn14:1.17.1": "Bấy giờ, này các tỳ-kheo, Bồ-tát Tỳ-bà-thi từ thân trời Đâu-suất qua đời, tỉnh giác chánh niệm, nhập vào thai mẹ.",
  "dn14:1.17.2": "Đó là pháp tánh ở đây.",
  "dn14:1.17.3": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát từ thân trời Đâu-suất qua đời và nhập vào thai mẹ.",
  "dn14:1.17.4": "Bấy giờ, trong thế gian này cùng với chư thiên, Ma vương, Phạm thiên, cùng quần sinh gồm sa-môn, bà-la-môn, chư thiên và loài người, một hào quang vô lượng rộng lớn hiện ra, vượt hẳn oai quang của chư thiên.",
  "dn14:1.17.5": "Ngay cả những khoảng không gian giữa các thế giới, tối tăm mịt mù, nơi mà mặt trăng và mặt trời dù có đại thần lực, đại oai lực như vậy cũng không chiếu tới được, tại đó cũng hiện ra một hào quang vô lượng rộng lớn, vượt hẳn oai quang của chư thiên.",
  "dn14:1.17.6": "Những chúng sinh sinh ở đó cũng nhờ ánh sáng ấy mà nhận biết nhau: ‘Thì ra, thưa bạn, còn có những chúng sinh khác sinh ở đây nữa.’",
  "dn14:1.17.7": "Và thế giới đại thiên gồm mười ngàn thế giới này rung chuyển, chấn động, dao động mạnh. Một hào quang vô lượng rộng lớn hiện ra trong đời, vượt hẳn oai quang của chư thiên.",
  "dn14:1.17.8": "Đó là pháp tánh ở đây.",
  "dn14:1.17.9": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát đã nhập vào thai mẹ, bốn vị thiên tử đến từ bốn phương để hộ vệ Ngài: ‘Chớ để người hay phi nhân nào, bất cứ ai, làm hại Bồ-tát hay mẹ của Bồ-tát.’",
  "dn14:1.17.10": "Đó là pháp tánh ở đây.",
  "dn14:1.18.1": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát đã nhập vào thai mẹ, mẹ của Bồ-tát tự nhiên là người có giới hạnh, từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ rượu men, rượu nấu và các chất say là chỗ buông lung.",
  "dn14:1.18.2": "Đó là pháp tánh ở đây.",
  "dn14:1.19.1": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát đã nhập vào thai mẹ, nơi mẹ của Bồ-tát không khởi lên tâm dục liên hệ đến đàn ông, và mẹ của Bồ-tát không thể bị bất cứ người đàn ông nào xâm phạm với tâm nhiễm dục.",
  "dn14:1.19.2": "Đó là pháp tánh ở đây.",
  "dn14:1.20.1": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát đã nhập vào thai mẹ, mẹ của Bồ-tát được thọ hưởng năm dục công đức. Bà được đầy đủ và thụ hưởng năm dục công đức ấy.",
  "dn14:1.20.2": "Đó là pháp tánh ở đây.",
  "dn14:1.21.1": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát đã nhập vào thai mẹ, mẹ của Bồ-tát không mắc bất cứ bệnh hoạn nào. Mẹ của Bồ-tát sống an vui, thân không mệt mỏi, và thấy được Bồ-tát ở trong thai, đầy đủ tay chân và các bộ phận, các căn không khiếm khuyết.",
  "dn14:1.21.2": "Ví như, này các tỳ-kheo, một viên ngọc lưu ly đẹp, thuần tịnh, có tám mặt, được mài giũa khéo léo, trong suốt, sáng chói, không vẩn đục, đầy đủ mọi vẻ tốt đẹp. Trong đó có xâu một sợi chỉ xanh, vàng, đỏ, trắng hay màu vàng nhạt.",
  "dn14:1.21.3": "Một người có mắt sáng cầm nó trong tay mà quan sát: ‘Đây là viên ngọc lưu ly đẹp, thuần tịnh, có tám mặt, được mài giũa khéo léo, trong suốt, sáng chói, không vẩn đục, đầy đủ mọi vẻ tốt đẹp. Trong đó có xâu một sợi chỉ xanh, vàng, đỏ, trắng hay màu vàng nhạt.’",
  "dn14:1.21.4": "Cũng vậy, này các tỳ-kheo, khi Bồ-tát đã nhập vào thai mẹ, mẹ của Bồ-tát không mắc bất cứ bệnh hoạn nào, sống an vui, thân không mệt mỏi, và thấy được Bồ-tát ở trong thai, đầy đủ tay chân và các bộ phận, các căn không khiếm khuyết.",
  "dn14:1.21.5": "Đó là pháp tánh ở đây.",
  "dn14:1.22.1": "Này các tỳ-kheo, đó là pháp tánh: bảy ngày sau khi Bồ-tát ra đời, mẹ của Bồ-tát qua đời và sinh lên cõi trời Đâu-suất.",
  "dn14:1.22.2": "Đó là pháp tánh ở đây.",
  "dn14:1.23.1": "Này các tỳ-kheo, đó là pháp tánh: như những người phụ nữ khác mang thai chín hay mười tháng rồi sinh con, mẹ của Bồ-tát không sinh như vậy. Mẹ của Bồ-tát mang thai trọn mười tháng rồi mới sinh Bồ-tát.",
  "dn14:1.23.2": "Đó là pháp tánh ở đây.",
  "dn14:1.24.1": "Này các tỳ-kheo, đó là pháp tánh: như những người phụ nữ khác sinh con khi ngồi hay nằm, mẹ của Bồ-tát không sinh như vậy. Mẹ của Bồ-tát sinh con trong tư thế đứng.",
  "dn14:1.24.2": "Đó là pháp tánh ở đây.",
  "dn14:1.25.1": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát ra khỏi thai mẹ, chư thiên đón lấy trước, rồi sau đó loài người mới đón lấy.",
  "dn14:1.25.2": "Đó là pháp tánh ở đây.",
  "dn14:1.26.1": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát ra khỏi thai mẹ, trước khi chạm đất, bốn vị thiên tử đón lấy Ngài và đặt trước mặt mẹ: ‘Hoan hỷ lên, thưa hoàng hậu, một người con đại uy đức đã sinh ra cho bà.’",
  "dn14:1.26.2": "Đó là pháp tánh ở đây.",
  "dn14:1.27.1": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát ra khỏi thai mẹ, Ngài ra đời trong sạch, không dính nước ối, không dính đờm nhớt, không dính máu, không dính bất cứ vật ô uế nào, thanh tịnh và trong sạch.",
  "dn14:1.27.2": "Ví như, này các tỳ-kheo, một bảo châu được đặt trên tấm vải Kāsi, thì bảo châu không làm bẩn tấm vải Kāsi, và tấm vải Kāsi cũng không làm bẩn bảo châu.",
  "dn14:1.27.3": "Vì sao vậy?",
  "dn14:1.27.4": "Vì cả hai đều thanh tịnh.",
  "dn14:1.27.5": "Cũng vậy, này các tỳ-kheo, khi Bồ-tát ra khỏi thai mẹ, Ngài ra đời trong sạch, không dính nước ối, không dính đờm nhớt, không dính máu, không dính bất cứ vật ô uế nào, thanh tịnh và trong sạch.",
  "dn14:1.27.6": "Đó là pháp tánh ở đây.",
  "dn14:1.28.1": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát ra khỏi thai mẹ, từ giữa hư không hiện ra hai dòng nước, một mát một ấm, để tắm rửa cho Bồ-tát và cho mẹ.",
  "dn14:1.28.2": "Đó là pháp tánh ở đây.",
  "dn14:1.29.1": "Này các tỳ-kheo, đó là pháp tánh: khi vừa sinh ra, Bồ-tát đứng vững trên hai chân, quay mặt về phương bắc, bước đi bảy bước, có lọng trắng che trên đầu, nhìn khắp mọi phương và cất tiếng nói như sư tử: ‘Ta là bậc tối thượng ở đời, ta là bậc trưởng thượng ở đời, ta là bậc cao quý nhất ở đời. Đây là đời sống cuối cùng, nay không còn tái sinh nữa.’",
  "dn14:1.29.2": "Đó là pháp tánh ở đây.",
  "dn14:1.30.1": "Này các tỳ-kheo, đó là pháp tánh: khi Bồ-tát ra khỏi thai mẹ, bấy giờ trong thế gian này cùng với chư thiên, Ma vương, Phạm thiên, cùng quần sinh gồm sa-môn, bà-la-môn, chư thiên và loài người, một hào quang vô lượng rộng lớn hiện ra, vượt hẳn oai quang của chư thiên.",
  "dn14:1.30.2": "Ngay cả những khoảng không gian giữa các thế giới, tối tăm mịt mù, nơi mà mặt trăng và mặt trời dù có đại thần lực, đại oai lực như vậy cũng không chiếu tới được, tại đó cũng hiện ra một hào quang vô lượng rộng lớn, vượt hẳn oai quang của chư thiên.",
  "dn14:1.30.3": "Những chúng sinh sinh ở đó cũng nhờ ánh sáng ấy mà nhận biết nhau: ‘Thì ra, thưa bạn, còn có những chúng sinh khác sinh ở đây nữa.’",
  "dn14:1.30.4": "Và thế giới đại thiên gồm mười ngàn thế giới này rung chuyển, chấn động, dao động mạnh; một hào quang vô lượng rộng lớn hiện ra trong đời, vượt hẳn oai quang của chư thiên.",
  "dn14:1.30.5": "Đó là pháp tánh ở đây.",
  "dn14:1.31.0": "3. Ba mươi hai tướng của bậc đại nhân",
  "dn14:1.31.1": "Này các tỳ-kheo, khi thái tử Tỳ-bà-thi ra đời, người ta tâu lên vua Bandhumā rằng:",
  "dn14:1.31.2": "‘Tâu đại vương, con trai của ngài đã sinh, xin đại vương hãy xem.’",
  "dn14:1.31.3": "Này các tỳ-kheo, vua Bandhumā đã thấy thái tử Tỳ-bà-thi; thấy rồi, vua cho mời các bà-la-môn xem tướng đến và nói như sau:",
  "dn14:1.31.4": "‘Xin chư vị bà-la-môn xem tướng hãy xem thái tử.’",
  "dn14:1.31.5": "Này các tỳ-kheo, các bà-la-môn xem tướng đã thấy thái tử Tỳ-bà-thi; thấy rồi, họ tâu với vua Bandhumā như sau:",
  "dn14:1.31.6": "‘Xin đại vương hoan hỷ, con trai của ngài đã sinh ra là người đại uy đức. Đại vương thật có phước, thật khéo được lợi, vì trong dòng tộc của ngài đã sinh ra một người con như vậy.",
  "dn14:1.31.7": "Tâu đại vương, thái tử này đầy đủ ba mươi hai tướng của bậc đại nhân; đối với bậc đại nhân đầy đủ những tướng ấy chỉ có hai con đường, không có con đường nào khác.’",
  "dn14:1.31.8": "Nếu sống đời tại gia, vị ấy sẽ là vị vua Chuyển luân, bậc pháp vương chân chính, chinh phục bốn phương, chiến thắng, đạt được sự vững bền trong quốc độ, đầy đủ bảy báu.",
  "dn14:1.31.9": "Bảy báu ấy là những gì?",
  "dn14:1.31.10": "Đó là: luân bảo, tượng bảo, mã bảo, ngọc bảo, nữ bảo, gia chủ bảo, và thứ bảy là tướng quân bảo.",
  "dn14:1.31.11": "Lại nữa, vị ấy có hơn một ngàn người con, dũng mãnh, anh hùng, hình dung oai vệ, có khả năng nghiền nát quân địch.",
  "dn14:1.31.12": "Vị ấy chinh phục và an trú trên cõi đất này cho đến tận bờ biển, không dùng roi gậy, không dùng gươm giáo, mà bằng chánh pháp.",
  "dn14:1.31.13": "Nhưng nếu từ bỏ gia đình, xuất gia sống không gia đình, vị ấy sẽ thành bậc A-la-hán, Chánh Đẳng Giác, vén mở màn che cho đời.",
  "dn14:1.32.1": "Thưa thiên vương, do những tướng nào mà thái tử này đầy đủ ba mươi hai tướng của bậc đại nhân, mà bậc đại nhân có đủ những tướng ấy chỉ có hai con đường, không có con đường nào khác?",
  "dn14:1.32.2": "Nếu sống đời tại gia, vị ấy sẽ là vị vua Chuyển luân, bậc pháp vương chân chính, chinh phục bốn phương, chiến thắng, đạt được sự vững bền trong quốc độ, đầy đủ bảy báu.",
  "dn14:1.32.3": "Bảy báu ấy là những gì?",
  "dn14:1.32.4": "Đó là: luân bảo, tượng bảo, mã bảo, ngọc bảo, nữ bảo, gia chủ bảo, và thứ bảy là tướng quân bảo.",
  "dn14:1.32.5": "Lại nữa, vị ấy có hơn một ngàn người con, dũng mãnh, anh hùng, hình dung oai vệ, có khả năng nghiền nát quân địch.",
  "dn14:1.32.6": "Vị ấy chinh phục và an trú trên cõi đất này cho đến tận bờ biển, không dùng roi gậy, không dùng gươm giáo, mà bằng chánh pháp.",
  "dn14:1.32.7": "Nhưng nếu từ bỏ gia đình, xuất gia sống không gia đình, vị ấy sẽ thành bậc A-la-hán, Chánh Đẳng Giác, vén mở màn che cho đời. Thưa thiên vương, thái tử này có bàn chân đặt rất vững. Vì thái tử này có bàn chân đặt rất vững, đó là một trong những tướng đại nhân của bậc đại nhân.",
  "dn14:1.32.8": "Thưa thiên vương, dưới hai bàn chân của thái tử này hiện ra các bánh xe có ngàn căm, có vành, có trục, đầy đủ mọi phương diện. Vì dưới hai bàn chân của thái tử này hiện ra các bánh xe có ngàn căm, có vành, có trục, đầy đủ mọi phương diện, đó là một trong những tướng đại nhân của bậc đại nhân.",
  "dn14:1.32.9": "Thưa thiên vương, thái tử này có gót chân dài …",
  "dn14:1.32.10": "Thưa thiên vương, thái tử này có ngón tay ngón chân dài …",
  "dn14:1.32.11": "Thưa thiên vương, thái tử này có tay chân mềm mại, dịu êm …",
  "dn14:1.32.12": "Thưa thiên vương, thái tử này có tay chân như lưới …",
  "dn14:1.32.13": "Thưa thiên vương, thái tử này có bàn chân cong cao …",
  "dn14:1.32.14": "Thưa thiên vương, thái tử này có ống chân như nai chúa …",
  "dn14:1.32.15": "Thưa thiên vương, thái tử này khi đứng thẳng, không cúi xuống, vẫn lấy hai lòng bàn tay sờ và xoa được hai đầu gối …",
  "dn14:1.32.16": "Thưa thiên vương, thái tử này có tướng kín nam tàng ẩn …",
  "dn14:1.32.17": "Thưa thiên vương, thái tử này có sắc thân vàng, da như vàng ròng …",
  "dn14:1.32.18": "Thưa thiên vương, thái tử này có da mịn màng; vì da mịn màng nên bụi bặm không bám vào thân …",
  "dn14:1.32.19": "Thưa thiên vương, thái tử này mỗi lỗ chân lông chỉ mọc một sợi lông …",
  "dn14:1.32.20": "Thưa thiên vương, thái tử này có lông mọc hướng lên; các sợi lông mọc hướng lên, màu xanh đen như thuốc mắt, cuộn tròn, xoáy về bên phải …",
  "dn14:1.32.21": "Thưa thiên vương, thái tử này có thân hình ngay thẳng như Phạm thiên …",
  "dn14:1.32.22": "Thưa thiên vương, thái tử này có bảy chỗ đầy đặn …",
  "dn14:1.32.23": "Thưa thiên vương, thái tử này có phần thân trước như sư tử …",
  "dn14:1.32.24": "Thưa thiên vương, thái tử này có khoảng giữa hai vai đầy đặn …",
  "dn14:1.32.25": "Thưa thiên vương, thái tử này có thân hình tròn đều như cây ni-câu-đà; thân dài bao nhiêu thì sải tay rộng bấy nhiêu, sải tay rộng bao nhiêu thì thân dài bấy nhiêu …",
  "dn14:1.32.26": "Thưa thiên vương, thái tử này có hai vai tròn đầy cân đối …",
  "dn14:1.32.27": "Thưa thiên vương, thái tử này có vị giác thượng hạng …",
  "dn14:1.32.28": "Thưa thiên vương, thái tử này có quai hàm như sư tử …",
  "dn14:1.32.29": "Thưa thiên vương, thái tử này có bốn mươi chiếc răng …",
  "dn14:1.32.30": "Thưa thiên vương, thái tử này có răng đều đặn …",
  "dn14:1.32.31": "Thưa thiên vương, thái tử này có răng khít nhau …",
  "dn14:1.32.32": "Thưa thiên vương, thái tử này có răng nanh rất trắng …",
  "dn14:1.32.33": "Thưa thiên vương, thái tử này có lưỡi rộng dài …",
  "dn14:1.32.34": "Thưa thiên vương, thái tử này có giọng nói như Phạm thiên, tiếng nói như chim ca-lăng-tần-già …",
  "dn14:1.32.35": "Thưa thiên vương, thái tử này có mắt xanh thẫm …",
  "dn14:1.32.36": "Thưa thiên vương, thái tử này có hàng mi như bò cái …",
  "dn14:1.32.37": "Thưa thiên vương, giữa hai chân mày của thái tử này có một sợi lông trắng mọc lên, mềm như bông mịn. Vì giữa hai chân mày của thái tử này có một sợi lông trắng mọc lên, mềm như bông mịn, đó cũng là một trong những tướng đại nhân của bậc đại nhân.",
  "dn14:1.32.38": "Thưa thiên vương, thái tử này có đỉnh đầu nhô cao. Vì thái tử này có đỉnh đầu nhô cao, đó là một trong những tướng đại nhân của bậc đại nhân.",
  "dn14:1.33.1": "Thưa thiên vương, thái tử này đầy đủ ba mươi hai tướng của bậc đại nhân; bậc đại nhân có đủ những tướng ấy chỉ có hai con đường, không có con đường nào khác.",
  "dn14:1.33.2": "Nếu sống đời tại gia, vị ấy sẽ là vị vua Chuyển luân, bậc pháp vương chân chính, chinh phục bốn phương, chiến thắng, đạt được sự vững bền trong quốc độ, đầy đủ bảy báu.",
  "dn14:1.33.3": "Bảy báu ấy là những gì?",
  "dn14:1.33.4": "Đó là: luân bảo, tượng bảo, mã bảo, ngọc bảo, nữ bảo, gia chủ bảo, và thứ bảy là tướng quân bảo.",
  "dn14:1.33.5": "Lại nữa, vị ấy có hơn một ngàn người con, dũng mãnh, anh hùng, hình dung oai vệ, có khả năng nghiền nát quân địch.",
  "dn14:1.33.6": "Vị ấy chinh phục và an trú trên cõi đất này cho đến tận bờ biển, không dùng roi gậy, không dùng gươm giáo, mà bằng chánh pháp.",
  "dn14:1.33.7": "Nhưng nếu từ bỏ gia đình, xuất gia sống không gia đình, vị ấy sẽ thành bậc A-la-hán, Chánh Đẳng Giác, vén mở màn che cho đời.",
  "dn14:1.33.8.0": "4. Danh xưng Vipassī",
  "dn14:1.33.9": "Bấy giờ, này các Tỳ-kheo, vua Bandhumā cho các bà-la-môn xem tướng mặc những tấm vải chưa từng dùng và làm cho họ thỏa mãn với mọi dục lạc.",
  "dn14:1.34.1": "Bấy giờ, này các Tỳ-kheo, vua Bandhumā cho sắp đặt những người nhũ mẫu để hầu hạ thái tử Vipassī.",
  "dn14:1.34.2": "Người thì cho bú sữa, người thì tắm rửa, người thì bồng bế, người thì ẵm trên tay chăm nom.",
  "dn14:1.34.3": "Khi thái tử Vipassī vừa sinh ra, người ta che lọng trắng cho ngài cả ngày lẫn đêm:",
  "dn14:1.34.4": "“Đừng để lạnh hay nóng, cỏ, bụi hay sương làm hại ngài.”",
  "dn14:1.34.5": "Này các Tỳ-kheo, khi vừa sinh ra, thái tử Vipassī được nhiều người yêu mến, khả ái.",
  "dn14:1.34.6": "Ví như, này các Tỳ-kheo, hoa sen xanh, sen hồng hay sen trắng được nhiều người yêu mến, khả ái;",
  "dn14:1.34.7": "cũng vậy, này các Tỳ-kheo, thái tử Vipassī được nhiều người yêu mến, khả ái.",
  "dn14:1.34.8": "Ngài thường được bồng từ lòng người này sang lòng người khác.",
  "dn14:1.35.1": "Này các Tỳ-kheo, khi vừa sinh ra, thái tử Vipassī có giọng nói trong trẻo, rõ ràng, ngọt ngào và dễ mến.",
  "dn14:1.35.2": "Ví như, này các Tỳ-kheo, trên núi Tuyết có loài chim tên là ca-lăng-tần-già, có tiếng hót trong trẻo, rõ ràng, ngọt ngào và dễ mến;",
  "dn14:1.35.3": "cũng vậy, này các Tỳ-kheo, thái tử Vipassī có giọng nói trong trẻo, rõ ràng, ngọt ngào và dễ mến.",
  "dn14:1.36.1": "Này các Tỳ-kheo, khi thái tử Vipassī vừa sinh ra, thiên nhãn do nghiệp quả phát sinh hiện ra nơi ngài, nhờ đó ngài thấy được quanh mình một do-tuần cả ngày lẫn đêm.",
  "dn14:1.37.1": "Này các Tỳ-kheo, khi vừa sinh ra, thái tử Vipassī nhìn không chớp mắt, như chư thiên cõi Tam thập tam.",
  "dn14:1.37.2": "Này các Tỳ-kheo, vì thái tử nhìn không chớp mắt nên danh xưng “Vipassī, Vipassī” đã khởi lên cho thái tử Vipassī.",
  "dn14:1.37.3": "Bấy giờ, này các Tỳ-kheo, vua Bandhumā ngồi xử việc, cho thái tử Vipassī ngồi trên lòng mình rồi dạy bảo về các công việc.",
  "dn14:1.37.4": "Khi ấy, này các Tỳ-kheo, thái tử Vipassī ngồi trên lòng cha, xem xét kỹ lưỡng rồi phân xử các việc đúng theo lẽ phải.",
  "dn14:1.37.5": "Này các Tỳ-kheo, vì thái tử xem xét kỹ lưỡng rồi phân xử các việc đúng theo lẽ phải, nên danh xưng “Vipassī, Vipassī” lại càng được gọi nhiều hơn nữa cho thái tử Vipassī.",
  "dn14:1.38.1": "Bấy giờ, này các Tỳ-kheo, vua Bandhumā cho xây ba cung điện cho thái tử Vipassī: một cho mùa mưa, một cho mùa lạnh, một cho mùa nóng;",
  "dn14:1.38.2": "và cho sẵn năm món dục lạc.",
  "dn14:1.38.3": "Tại đó, này các Tỳ-kheo, thái tử Vipassī ở trong cung điện mùa mưa suốt bốn tháng, được hầu hạ bởi các nhạc công không có nam giới, và không bước xuống lầu dưới.",
  "dn14:1.38.4": "Phần tụng đọc thứ nhất.",
  "dn14:2.1.0": "5. Người già",
  "dn14:2.1.1": "Bấy giờ, này các Tỳ-kheo, sau nhiều năm, nhiều trăm năm, nhiều ngàn năm, thái tử Vipassī gọi người đánh xe đến:",
  "dn14:2.1.2": "“Này người đánh xe thân mến, hãy thắng những cỗ xe tốt đẹp. Chúng ta sẽ đi đến vườn ngự uyển để xem cảnh đẹp.”",
  "dn14:2.1.3": "“Vâng, thưa ngài,” này các Tỳ-kheo, người đánh xe vâng lời thái tử Vipassī, thắng những cỗ xe tốt đẹp rồi tâu với thái tử Vipassī:",
  "dn14:2.1.4": "“Thưa ngài, những cỗ xe tốt đẹp đã được thắng xong,",
  "dn14:2.1.5": "xin ngài tùy thời.”",
  "dn14:2.1.6": "Bấy giờ, này các Tỳ-kheo, thái tử Vipassī lên cỗ xe tốt đẹp và đi đến vườn ngự uyển bằng những cỗ xe tốt đẹp.",
  "dn14:2.2.1": "Này các Tỳ-kheo, khi đang đi đến vườn ngự uyển, thái tử Vipassī thấy một người già, lưng còng như đòn tay mái nhà, cong quắp, chống gậy, run rẩy mà đi, bệnh hoạn, tuổi xuân đã qua.",
  "dn14:2.2.2": "Thấy vậy, ngài gọi người đánh xe:",
  "dn14:2.2.3": "“Này người đánh xe thân mến, người này là sao vậy?",
  "dn14:2.2.4": "Tóc của ông ta không như những người khác, thân thể của ông ta cũng không như những người khác.”",
  "dn14:2.2.5": "“Thưa ngài, đó là người già.”",
  "dn14:2.2.6": "“Này người đánh xe thân mến, thế nào gọi là người già?”",
  "dn14:2.2.7": "“Thưa ngài, đó gọi là người già. Người ấy nay không còn sống được bao lâu nữa.”",
  "dn14:2.2.8": "“Này người đánh xe thân mến, vậy ta cũng là người phải già, chưa vượt khỏi già sao?”",
  "dn14:2.2.9": "“Thưa ngài, cả ngài lẫn chúng tôi, tất cả đều là những kẻ phải già, chưa vượt khỏi già.”",
  "dn14:2.2.10": "“Vậy thì thôi, này người đánh xe thân mến, hôm nay không cần đi vườn ngự uyển nữa. Hãy quay xe trở về nội cung ngay từ đây.”",
  "dn14:2.2.11": "“Vâng, thưa ngài,” này các Tỳ-kheo, người đánh xe vâng lời thái tử Vipassī rồi quay xe trở về nội cung ngay từ đó.",
  "dn14:2.2.12": "Tại đó, này các Tỳ-kheo, thái tử Vipassī trở về nội cung, buồn khổ, sầu muộn, trầm tư:",
  "dn14:2.2.13": "“Thật đáng chán thay cái gọi là sinh, vì hễ đã sinh ra thì già phải hiện rõ.”",
  "dn14:2.3.1": "Bấy giờ, này các Tỳ-kheo, vua Bandhumā cho gọi người đánh xe đến và nói như sau:",
  "dn14:2.3.2": "“Này người đánh xe thân mến, có phải thái tử đã vui thích ở vườn ngự uyển chăng? Có phải thái tử đã hoan hỷ ở vườn ngự uyển chăng?”",
  "dn14:2.3.3": "“Thưa ngài, thái tử không vui thích ở vườn ngự uyển, thái tử cũng không hoan hỷ ở vườn ngự uyển.”",
  "dn14:2.3.4": "“Nhưng này người đánh xe thân mến, khi đang đi đến vườn ngự uyển, thái tử đã thấy gì?”",
  "dn14:2.3.5": "“Thưa ngài, khi đang đi đến vườn ngự uyển, thái tử đã thấy một người già, lưng còng như đòn tay mái nhà, cong quắp, chống gậy, run rẩy mà đi, bệnh hoạn, tuổi xuân đã qua.",
  "dn14:2.3.6": "Thấy vậy, ngài nói với tôi như sau:",
  "dn14:2.3.7": "“Này người đánh xe thân mến, người này bị sao vậy, tóc của ông ấy không như những người khác, thân thể của ông ấy cũng không như những người khác?”",
  "dn14:2.3.8": "“Tâu thiên tử, đó là người già.”",
  "dn14:2.3.9": "“Này người đánh xe thân mến, thế nào gọi là người già?”",
  "dn14:2.3.10": "“Tâu thiên tử, gọi là người già tức là từ nay người ấy sẽ không còn sống được bao lâu nữa.”",
  "dn14:2.3.11": "“Này người đánh xe thân mến, vậy ta cũng là kẻ phải già, không vượt khỏi già sao?”",
  "dn14:2.3.12": "“Tâu thiên tử, ngài và cả chúng tôi, tất cả đều là những kẻ phải già, không vượt khỏi già.”",
  "dn14:2.3.13": "“Vậy thì, này người đánh xe thân mến, hôm nay đi đến vườn ngự thế là đủ rồi, hãy quay xe trở về nội cung ngay từ đây.”",
  "dn14:2.3.14": "“Vâng, thưa thiên tử.” Tâu thiên tử, tôi đã vâng lời thái tử Vipassī rồi từ đó quay xe trở về nội cung.",
  "dn14:2.3.15": "Tâu thiên tử, thái tử đi vào nội cung rồi, buồn khổ, sầu muộn, trầm tư:",
  "dn14:2.3.16": "“Than ôi, cái gọi là sinh thật đáng chán thay, vì hễ đã sinh ra thì già sẽ hiện rõ.”",
  "dn14:2.4.0": "6. Người bệnh",
  "dn14:2.4.1": "Rồi này các Tỳ-kheo, vua Bandhumā nghĩ như sau:",
  "dn14:2.4.2": "‘Mong sao thái tử Vipassī đừng không trị vì vương quốc, mong sao thái tử Vipassī đừng từ bỏ gia đình để xuất gia, mong sao lời nói của các bà-la-môn đoán tướng đừng thành sự thật.’",
  "dn14:2.4.3": "Rồi này các Tỳ-kheo, vua Bandhumā càng cho bày biện năm dục trưởng dưỡng cho thái tử Vipassī nhiều hơn nữa:",
  "dn14:2.4.4": "‘để thái tử Vipassī trị vì vương quốc, để thái tử Vipassī không từ bỏ gia đình mà xuất gia, để lời nói của các bà-la-môn đoán tướng trở thành sai lầm.’",
  "dn14:2.4.5": "Này các Tỳ-kheo, tại đó thái tử Vipassī được đầy đủ, thụ hưởng trọn vẹn năm dục.",
  "dn14:2.5.1": "Rồi này các Tỳ-kheo, sau nhiều năm…",
  "dn14:2.6.1": "Này các Tỳ-kheo, khi thái tử Vipassī đang đi ra vườn ngự, ngài thấy một người bệnh, đau đớn, bệnh nặng, nằm vùi trong phân và nước tiểu của chính mình, được người khác đỡ dậy, được người khác đặt nằm xuống.",
  "dn14:2.6.2": "Thấy vậy, ngài gọi người đánh xe:",
  "dn14:2.6.3": "‘Này người đánh xe thân mến, người này bị sao vậy?",
  "dn14:2.6.4": "Mắt của ông ấy không như những người khác, giọng nói của ông ấy cũng không như những người khác?’",
  "dn14:2.6.5": "‘Tâu thiên tử, đó là người bệnh.’",
  "dn14:2.6.6": "‘Này người đánh xe thân mến, thế nào gọi là người bệnh?’",
  "dn14:2.6.7": "‘Tâu thiên tử, gọi là người bệnh tức là may ra người ấy có thể khỏi được cơn bệnh ấy.’",
  "dn14:2.6.8": "‘Này người đánh xe thân mến, vậy ta cũng là kẻ phải bệnh, không vượt khỏi bệnh sao?’",
  "dn14:2.6.9": "‘Tâu thiên tử, ngài và cả chúng tôi, tất cả đều là những kẻ phải bệnh, không vượt khỏi bệnh.’",
  "dn14:2.6.10": "‘Vậy thì, này người đánh xe thân mến, hôm nay đi đến vườn ngự thế là đủ rồi, hãy quay xe trở về nội cung ngay từ đây.’",
  "dn14:2.6.11": "‘Vâng, thưa thiên tử.’ Này các Tỳ-kheo, người đánh xe đã vâng lời thái tử Vipassī rồi từ đó quay xe trở về nội cung.",
  "dn14:2.6.12": "Này các Tỳ-kheo, tại đó thái tử Vipassī đi vào nội cung rồi, buồn khổ, sầu muộn, trầm tư:",
  "dn14:2.6.13": "‘Than ôi, cái gọi là sinh thật đáng chán thay, vì hễ đã sinh ra thì già sẽ hiện rõ, bệnh sẽ hiện rõ.’",
  "dn14:2.7.1": "Rồi này các Tỳ-kheo, vua Bandhumā cho gọi người đánh xe đến và nói như sau:",
  "dn14:2.7.2": "‘Này người đánh xe thân mến, có phải thái tử đã vui thích ở vườn ngự chăng, có phải thái tử đã hoan hỷ ở vườn ngự chăng?’",
  "dn14:2.7.3": "‘Tâu thiên tử, không, thái tử không vui thích ở vườn ngự, không hoan hỷ ở vườn ngự.’",
  "dn14:2.7.4": "‘Này người đánh xe thân mến, vậy khi đi ra vườn ngự, thái tử đã thấy gì?’",
  "dn14:2.7.5": "‘Tâu thiên tử, khi đi ra vườn ngự, thái tử đã thấy một người bệnh, đau đớn, bệnh nặng, nằm vùi trong phân và nước tiểu của chính mình, được người khác đỡ dậy, được người khác đặt nằm xuống.",
  "dn14:2.7.6": "Thấy vậy, ngài nói với tôi như sau:",
  "dn14:2.7.7": "“Này người đánh xe thân mến, người này bị sao vậy, mắt của ông ấy không như những người khác, giọng nói của ông ấy cũng không như những người khác?”",
  "dn14:2.7.8": "“Tâu thiên tử, đó là người bệnh.”",
  "dn14:2.7.9": "“Này người đánh xe thân mến, thế nào gọi là người bệnh?”",
  "dn14:2.7.10": "“Tâu thiên tử, gọi là người bệnh tức là may ra người ấy có thể khỏi được cơn bệnh ấy.”",
  "dn14:2.7.11": "“Này người đánh xe thân mến, vậy ta cũng là kẻ phải bệnh, không vượt khỏi bệnh sao?”",
  "dn14:2.7.12": "“Tâu thiên tử, ngài và cả chúng tôi, tất cả đều là những kẻ phải bệnh, không vượt khỏi bệnh.”",
  "dn14:2.7.13": "“Vậy thì, này người đánh xe thân mến, hôm nay đi đến vườn ngự thế là đủ rồi, hãy quay xe trở về nội cung ngay từ đây.”",
  "dn14:2.7.14": "“Vâng, thưa thiên tử.” Tâu thiên tử, tôi đã vâng lời thái tử Vipassī rồi từ đó quay xe trở về nội cung.",
  "dn14:2.7.15": "Tâu thiên tử, thái tử đi vào nội cung rồi, buồn khổ, sầu muộn, trầm tư:",
  "dn14:2.7.16": "“Than ôi, cái gọi là sinh thật đáng chán thay, vì hễ đã sinh ra thì già sẽ hiện rõ, bệnh sẽ hiện rõ.”",
  "dn14:2.8.0": "7. Người chết",
  "dn14:2.8.1": "Rồi này các Tỳ-kheo, vua Bandhumā nghĩ như sau:",
  "dn14:2.8.2": "‘Mong sao thái tử Vipassī đừng không trị vì vương quốc, mong sao thái tử Vipassī đừng từ bỏ gia đình để xuất gia, mong sao lời nói của các bà-la-môn đoán tướng đừng thành sự thật.’",
  "dn14:2.8.3": "Rồi này các Tỳ-kheo, vua Bandhumā càng cho bày biện năm dục trưởng dưỡng cho thái tử Vipassī nhiều hơn nữa:",
  "dn14:2.8.4": "‘để thái tử Vipassī trị vì vương quốc, để thái tử Vipassī không từ bỏ gia đình mà xuất gia, để lời nói của các bà-la-môn đoán tướng trở thành sai lầm.’",
  "dn14:2.9.1": "Này các Tỳ-kheo, tại đó thái tử Vipassī được đầy đủ, thụ hưởng trọn vẹn năm dục.",
  "dn14:2.9.2": "Rồi này các Tỳ-kheo, sau nhiều năm…",
  "dn14:2.10.1": "Này các Tỳ-kheo, khi thái tử Vipassī đang đi ra vườn ngự, ngài thấy một đám đông tụ họp, đang chuẩn bị nhiều loại vải vóc đủ màu.",
  "dn14:2.10.2": "Thấy vậy, ngài gọi người đánh xe:",
  "dn14:2.10.3": "‘Này người đánh xe thân mến, đám đông kia tụ họp làm gì mà đang chuẩn bị nhiều loại vải vóc đủ màu vậy?’",
  "dn14:2.10.4": "‘Tâu thiên tử, đó là một người đã chết.’",
  "dn14:2.10.5": "‘Vậy thì, này người đánh xe thân mến, hãy cho xe đi đến chỗ người chết ấy.’",
  "dn14:2.10.6": "‘Vâng, thưa thiên tử.’ Này các Tỳ-kheo, người đánh xe đã vâng lời thái tử Vipassī rồi cho xe đi đến chỗ người chết ấy.",
  "dn14:2.10.7": "Này các Tỳ-kheo, thái tử Vipassī thấy người đã chết, thấy vậy ngài gọi người đánh xe:",
  "dn14:2.10.8": "‘Này người đánh xe thân mến, thế nào gọi là người chết?’",
  "dn14:2.10.9": "‘Tâu thiên tử, gọi là người chết tức là từ nay mẹ cha hay những bà con huyết thống khác sẽ không còn thấy người ấy nữa, và chính người ấy cũng sẽ không còn thấy mẹ cha hay những bà con huyết thống khác nữa.’",
  "dn14:2.10.10": "‘Này người đánh xe thân mến, vậy ta cũng là kẻ phải chết, không vượt khỏi chết;",
  "dn14:2.10.11": "mẹ ta hay cha ta hoặc những bà con huyết thống khác cũng sẽ không còn thấy ta;",
  "dn14:2.10.12": "và ta cũng sẽ không còn thấy mẹ ta hay cha ta hoặc những bà con huyết thống khác nữa sao?’",
  "dn14:2.10.13": "‘Tâu thiên tử, ngài và cả chúng tôi, tất cả đều là những kẻ phải chết, không vượt khỏi chết;",
  "dn14:2.10.14": "mẹ cha hay những bà con huyết thống khác cũng sẽ không còn thấy ngài;",
  "dn14:2.10.15": "và ngài cũng sẽ không còn thấy mẹ cha hay những bà con huyết thống khác nữa.’",
  "dn14:2.10.16": "‘Vậy thì, này người đánh xe thân mến, hôm nay đi đến vườn ngự thế là đủ rồi, hãy quay xe trở về nội cung ngay từ đây.’",
  "dn14:2.10.17": "‘Vâng, thưa thiên tử.’ Này các Tỳ-kheo, người đánh xe đã vâng lời thái tử Vipassī rồi từ đó quay xe trở về nội cung.",
  "dn14:2.10.18": "Này các Tỳ-kheo, tại đó thái tử Vipassī đi vào nội cung rồi, buồn khổ, sầu muộn, trầm tư:",
  "dn14:2.10.19": "‘Than ôi, cái gọi là sinh thật đáng chán thay, vì hễ đã sinh ra thì già sẽ hiện rõ, bệnh sẽ hiện rõ, chết sẽ hiện rõ.’",
  "dn14:2.11.1": "Rồi này các Tỳ-kheo, vua Bandhumā cho gọi người đánh xe đến và nói như sau:",
  "dn14:2.11.2": "‘Này người đánh xe thân mến, có phải thái tử đã vui thích ở vườn ngự chăng, có phải thái tử đã hoan hỷ ở vườn ngự chăng?’",
  "dn14:2.11.3": "‘Tâu thiên tử, không, thái tử không vui thích ở vườn ngự, không hoan hỷ ở vườn ngự.’",
  "dn14:2.11.4": "‘Này người đánh xe thân mến, vậy khi đi ra vườn ngự, thái tử đã thấy gì?’",
  "dn14:2.11.5": "‘Tâu thiên tử, khi đi ra vườn ngự, thái tử đã thấy một đám đông tụ họp, đang chuẩn bị nhiều loại vải vóc đủ màu.",
  "dn14:2.11.6": "Thấy vậy, ngài nói với tôi như sau:",
  "dn14:2.11.7": "“Này người đánh xe thân mến, đám đông kia tụ họp làm gì mà đang chuẩn bị nhiều loại vải vóc đủ màu vậy?”",
  "dn14:2.11.8": "“Tâu thiên tử, đó là một người đã chết.”",
  "dn14:2.11.9": "“Vậy thì, này người đánh xe thân mến, hãy cho xe đi đến chỗ người chết ấy.”",
  "dn14:2.11.10": "“Vâng, thưa thiên tử.” Tâu thiên tử, tôi đã vâng lời thái tử Vipassī rồi cho xe đi đến chỗ người chết ấy.",
  "dn14:2.11.11": "Tâu thiên tử, thái tử đã thấy người đã chết, thấy vậy ngài nói với tôi như sau:",
  "dn14:2.11.12": "“Này người đánh xe thân mến, thế nào gọi là người chết?”",
  "dn14:2.11.13": "“Tâu thiên tử, đó gọi là người chết.",
  "dn14:2.11.14": "Từ nay mẹ cha hay những bà con huyết thống khác sẽ không còn thấy người ấy nữa, và chính người ấy cũng sẽ không còn thấy mẹ cha hay những bà con huyết thống khác nữa.”",
  "dn14:2.11.15": "“Này người đánh xe thân mến, vậy ta cũng là kẻ phải chết, không vượt khỏi chết;",
  "dn14:2.11.16": "mẹ ta hay cha ta hoặc những bà con huyết thống khác cũng sẽ không còn thấy ta;",
  "dn14:2.11.17": "và ta cũng sẽ không còn thấy mẹ ta hay cha ta hoặc những bà con huyết thống khác nữa sao?”",
  "dn14:2.11.18": "“Tâu thiên tử, ngài và cả chúng tôi, tất cả đều là những kẻ phải chết, không vượt khỏi chết;",
  "dn14:2.11.19": "mẹ cha hay những bà con huyết thống khác cũng sẽ không còn thấy ngài, và ngài cũng sẽ không còn thấy mẹ cha hay những bà con huyết thống khác nữa.”",
  "dn14:2.11.20": "“Vậy thì, này người đánh xe thân mến, hôm nay đi đến vườn ngự thế là đủ rồi, hãy quay xe trở về nội cung ngay từ đây.”",
  "dn14:2.11.21": "“Vâng, thưa thiên tử.” Tâu thiên tử, tôi đã vâng lời thái tử Vipassī rồi từ đó quay xe trở về nội cung.",
  "dn14:2.11.22": "Tâu thiên tử, thái tử đi vào nội cung rồi, buồn khổ, sầu muộn, trầm tư:",
  "dn14:2.11.23": "“Than ôi, cái gọi là sinh thật đáng chán thay, vì hễ đã sinh ra thì già sẽ hiện rõ, bệnh sẽ hiện rõ, chết sẽ hiện rõ.”",
  "dn14:2.12.0": "8. Người xuất gia",
  "dn14:2.12.1": "Rồi này các Tỳ-kheo, vua Bandhumā nghĩ như sau:",
  "dn14:2.12.2": "‘Mong sao thái tử Vipassī đừng không trị vì vương quốc, mong sao thái tử Vipassī đừng từ bỏ gia đình để xuất gia, mong sao lời nói của các bà-la-môn đoán tướng đừng thành sự thật.’",
  "dn14:2.12.3": "Rồi này các Tỳ-kheo, vua Bandhumā càng cho bày biện năm dục trưởng dưỡng cho thái tử Vipassī nhiều hơn nữa:",
  "dn14:2.12.4": "‘để thái tử Vipassī trị vì vương quốc, để thái tử Vipassī không từ bỏ gia đình mà xuất gia, để lời nói của các bà-la-môn đoán tướng trở thành sai lầm.’",
  "dn14:2.13.1": "Tại đó, này các Tỳ-kheo, thái tử Vipassī được đầy đủ và thọ hưởng năm dục công đức.",
  "dn14:2.13.2": "Rồi này các Tỳ-kheo, sau khi nhiều năm, nhiều trăm năm, nhiều ngàn năm đã trôi qua, thái tử Vipassī gọi người đánh xe:",
  "dn14:2.13.3": "‘Này người đánh xe thân mến, hãy thắng những cỗ xe tốt đẹp tốt đẹp, chúng ta sẽ đi đến vườn ngự uyển để xem cảnh đất đẹp.’",
  "dn14:2.13.4": "‘Vâng, thưa ngài,’ này các Tỳ-kheo, người đánh xe vâng lời thái tử Vipassī, cho thắng những cỗ xe tốt đẹp tốt đẹp rồi tâu với thái tử Vipassī:",
  "dn14:2.13.5": "‘Tâu ngài, những cỗ xe tốt đẹp tốt đẹp đã được thắng xong,",
  "dn14:2.13.6": "xin ngài nghĩ là đã đến lúc nào thì đi.’",
  "dn14:2.13.7": "Rồi này các Tỳ-kheo, thái tử Vipassī lên cỗ xe tốt đẹp tốt đẹp, với những cỗ xe tốt đẹp tốt đẹp đi ra vườn ngự uyển.",
  "dn14:2.14.1": "Này các Tỳ-kheo, khi đang đi ra vườn ngự uyển, thái tử Vipassī thấy một người xuất gia, đầu cạo trọc, mặc y ca-sa.",
  "dn14:2.14.2": "Thấy vậy, ngài gọi người đánh xe:",
  "dn14:2.14.3": "‘Này người đánh xe thân mến, người này là hạng người gì?",
  "dn14:2.14.4": "Đầu của người ấy không giống như những người khác, y phục của người ấy cũng không giống như những người khác?’",
  "dn14:2.14.5": "‘Tâu ngài, đó là người xuất gia.’",
  "dn14:2.14.6": "‘Này người đánh xe thân mến, thế nào gọi là người xuất gia?’",
  "dn14:2.14.7": "‘Tâu ngài, người gọi là xuất gia là người sống theo pháp lành, sống đúng đắn lành, làm các việc thiện lành, làm các công đức lành, không hại lành, thương xót các loài hữu tình lành.’",
  "dn14:2.14.8": "‘Lành thay, này người đánh xe thân mến, người gọi là xuất gia thật là tốt: sống theo pháp lành, sống đúng đắn lành, làm các việc thiện lành, làm các công đức lành, không hại lành, thương xót các loài hữu tình lành.",
  "dn14:2.14.9": "Vậy thì, này người đánh xe thân mến, hãy cho xe đi đến chỗ người xuất gia ấy.’",
  "dn14:2.14.10": "‘Vâng, thưa ngài,’ này các Tỳ-kheo, người đánh xe vâng lời thái tử Vipassī, cho xe đi đến chỗ người xuất gia ấy.",
  "dn14:2.14.11": "Rồi này các Tỳ-kheo, thái tử Vipassī nói với người xuất gia ấy như sau:",
  "dn14:2.14.12": "‘Này hiền giả, ông là hạng người gì,",
  "dn14:2.14.13": "mà đầu của ông không giống như những người khác, y phục của ông cũng không giống như những người khác?’",
  "dn14:2.14.14": "‘Tâu ngài, tôi là người xuất gia.’",
  "dn14:2.14.15": "‘Này hiền giả, thế nào gọi là người xuất gia?’",
  "dn14:2.14.16": "‘Tâu ngài, tôi là người xuất gia, tức là người sống theo pháp lành, sống đúng đắn lành, làm các việc thiện lành, làm các công đức lành, không hại lành, thương xót các loài hữu tình lành.’",
  "dn14:2.14.17": "‘Lành thay, này hiền giả, ông là người xuất gia: sống theo pháp lành, sống đúng đắn lành, làm các việc thiện lành, làm các công đức lành, không hại lành, thương xót các loài hữu tình lành.’",
  "dn14:2.15.0": "9. Bồ-tát xuất gia",
  "dn14:2.15.1": "Rồi này các Tỳ-kheo, thái tử Vipassī gọi người đánh xe:",
  "dn14:2.15.2": "‘Vậy thì, này người đánh xe thân mến, hãy đem xe trở về nội cung từ đây.",
  "dn14:2.15.3": "Còn ta, ngay tại đây sẽ cạo bỏ tóc râu, đắp y ca-sa, từ bỏ gia đình, xuất gia sống không gia đình.’",
  "dn14:2.15.4": "‘Vâng, thưa ngài,’ này các Tỳ-kheo, người đánh xe vâng lời thái tử Vipassī, đem xe trở về nội cung ngay từ đó.",
  "dn14:2.15.5": "Còn thái tử Vipassī, ngay tại chỗ ấy cạo bỏ tóc râu, đắp y ca-sa, từ bỏ gia đình, xuất gia sống không gia đình.",
  "dn14:2.16.0": "10. Đại chúng cùng xuất gia theo",
  "dn14:2.16.1": "Này các Tỳ-kheo, đại chúng ở kinh đô Bandhumatī, gồm tám vạn bốn ngàn người, đã nghe rằng:",
  "dn14:2.16.2": "‘Nghe nói thái tử Vipassī đã cạo bỏ tóc râu, đắp y ca-sa, từ bỏ gia đình, xuất gia sống không gia đình.’",
  "dn14:2.16.3": "Nghe xong, họ nghĩ rằng:",
  "dn14:2.16.4": "‘Chắc hẳn pháp luật ấy không phải là tầm thường, sự xuất gia ấy không phải là tầm thường, nên thái tử Vipassī mới cạo bỏ tóc râu, đắp y ca-sa, từ bỏ gia đình, xuất gia sống không gia đình.",
  "dn14:2.16.5": "Nếu ngay cả thái tử Vipassī còn cạo bỏ tóc râu, đắp y ca-sa, từ bỏ gia đình, xuất gia sống không gia đình, huống nữa là chúng ta.’",
  "dn14:2.16.6": "Rồi này các Tỳ-kheo, đại chúng ấy gồm tám vạn bốn ngàn người cạo bỏ tóc râu, đắp y ca-sa, theo Bồ-tát Vipassī đã xuất gia từ bỏ gia đình, sống không gia đình mà xuất gia theo.",
  "dn14:2.16.7": "Này các Tỳ-kheo, được hội chúng ấy vây quanh, Bồ-tát Vipassī du hành qua các làng, thị trấn, xứ sở và kinh thành.",
  "dn14:2.17.1": "Rồi này các Tỳ-kheo, khi Bồ-tát Vipassī đi đến chỗ thanh vắng, sống viễn ly, tâm ngài khởi lên suy tư như sau:",
  "dn14:2.17.2": "‘Thật không thích hợp cho ta khi sống chen chúc như thế này; hay là ta nên sống một mình, tách khỏi đoàn chúng.’",
  "dn14:2.17.3": "Rồi này các Tỳ-kheo, sau một thời gian, Bồ-tát Vipassī sống một mình, tách khỏi đoàn chúng; tám vạn bốn ngàn người xuất gia ấy đi theo một đường khác, còn Bồ-tát Vipassī đi theo một con đường khác.",
  "dn14:2.18.0": "11. Bồ-tát chuyên chú quán sát",
  "dn14:2.18.1": "Rồi này các Tỳ-kheo, khi Bồ-tát Vipassī đã an trú, đi đến chỗ thanh vắng, sống viễn ly, tâm ngài khởi lên suy tư như sau:",
  "dn14:2.18.2": "‘Thế gian này thật rơi vào khốn khó: sinh ra rồi già đi, rồi chết, rồi qua đời, rồi tái sinh; thế mà lại không biết lối thoát khỏi khổ này, khỏi già chết,",
  "dn14:2.18.3": "bao giờ mới có thể nhận ra lối thoát khỏi khổ này, khỏi già chết?’",
  "dn14:2.18.4": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.5": "‘Do có cái gì mà già chết có mặt? Già chết do duyên gì?’",
  "dn14:2.18.6": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.7": "‘Do có sinh nên có già chết; già chết do sinh làm duyên.’",
  "dn14:2.18.8": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.9": "‘Do có cái gì mà sinh có mặt? Sinh do duyên gì?’",
  "dn14:2.18.10": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.11": "‘Do có hữu nên có sinh; sinh do hữu làm duyên.’",
  "dn14:2.18.12": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.13": "‘Do có cái gì mà hữu có mặt? Hữu do duyên gì?’",
  "dn14:2.18.14": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.15": "‘Do có chấp thủ nên có hữu; hữu do chấp thủ làm duyên.’",
  "dn14:2.18.16": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.17": "‘Do có cái gì mà chấp thủ có mặt? Chấp thủ do duyên gì?’",
  "dn14:2.18.18": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.19": "‘Do có ái nên có chấp thủ; chấp thủ do ái làm duyên.’",
  "dn14:2.18.20": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.21": "‘Do có cái gì mà ái có mặt? Ái do duyên gì?’",
  "dn14:2.18.22": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.23": "‘Do có thọ nên có ái; ái do thọ làm duyên.’",
  "dn14:2.18.24": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.25": "‘Do có cái gì mà thọ có mặt? Thọ do duyên gì?’",
  "dn14:2.18.26": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.27": "‘Do có xúc nên có thọ; thọ do xúc làm duyên.’",
  "dn14:2.18.28": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.29": "‘Do có cái gì mà xúc có mặt? Xúc do duyên gì?’",
  "dn14:2.18.30": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.31": "‘Do có sáu xứ nên có xúc; xúc do sáu xứ làm duyên.’",
  "dn14:2.18.32": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.33": "‘Do có cái gì mà sáu xứ có mặt? Sáu xứ do duyên gì?’",
  "dn14:2.18.34": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.35": "‘Do có danh sắc nên có sáu xứ; sáu xứ do danh sắc làm duyên.’",
  "dn14:2.18.36": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.37": "‘Do có cái gì mà danh sắc có mặt? Danh sắc do duyên gì?’",
  "dn14:2.18.38": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.39": "‘Do có thức nên có danh sắc; danh sắc do thức làm duyên.’",
  "dn14:2.18.40": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.18.41": "‘Do có cái gì mà thức có mặt? Thức do duyên gì?’",
  "dn14:2.18.42": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.18.43": "‘Do có danh sắc nên có thức; thức do danh sắc làm duyên.’",
  "dn14:2.19.1": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.19.2": "‘Thức này quay trở lui từ danh sắc, không đi xa hơn nữa.",
  "dn14:2.19.3": "Chỉ đến mức này là có thể sinh ra, già đi, chết đi, qua đời, tái sinh, tức là:",
  "dn14:2.19.4": "do danh sắc làm duyên nên có thức, do thức làm duyên nên có danh sắc, do danh sắc làm duyên nên có sáu xứ, do sáu xứ làm duyên nên có xúc, do xúc làm duyên nên có thọ, do thọ làm duyên nên có ái, do ái làm duyên nên có chấp thủ, do chấp thủ làm duyên nên có hữu, do hữu làm duyên nên có sinh, do sinh làm duyên nên phát sinh già chết, sầu, bi, khổ, ưu, não.",
  "dn14:2.19.5": "Như vậy là sự tập khởi của toàn bộ khối khổ này.’",
  "dn14:2.19.6": "Này các Tỳ-kheo, khi ấy đối với các pháp chưa từng được nghe trước đây, nơi Bồ-tát Vipassī khởi lên con mắt, khởi lên trí, khởi lên tuệ, khởi lên minh, khởi lên ánh sáng rằng: ‘Tập khởi, tập khởi.’",
  "dn14:2.20.1": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.20.2": "‘Do không có cái gì mà già chết không có mặt? Do sự diệt của cái gì mà già chết diệt?’",
  "dn14:2.20.3": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.20.4": "‘Do không có sinh nên không có già chết; do sinh diệt nên già chết diệt.’",
  "dn14:2.20.5": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.20.6": "‘Do không có cái gì mà sinh không có mặt? Do sự diệt của cái gì mà sinh diệt?’",
  "dn14:2.20.7": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ:",
  "dn14:2.20.8": "‘Do không có hữu nên không có sinh; do hữu diệt nên sinh diệt.’",
  "dn14:2.20.9": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ rằng:",
  "dn14:2.20.10": "‘Khi cái này không có thì hữu không có, do sự diệt của cái gì mà hữu diệt?’ ",
  "dn14:2.20.11": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ: ",
  "dn14:2.20.12": "‘Khi thủ không có thì hữu không có, do thủ diệt nên hữu diệt.’ ",
  "dn14:2.20.13": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ như sau: ",
  "dn14:2.20.14": "‘Khi cái gì không có thì thủ không có, do sự diệt của cái gì mà thủ diệt?’ ",
  "dn14:2.20.15": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ: ",
  "dn14:2.20.16": "‘Khi ái không có thì thủ không có, do ái diệt nên thủ diệt.’ ",
  "dn14:2.20.17": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ như sau: ",
  "dn14:2.20.18": "‘Khi cái gì không có thì ái không có, do sự diệt của cái gì mà ái diệt?’ ",
  "dn14:2.20.19": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ: ",
  "dn14:2.20.20": "‘Khi thọ không có thì ái không có, do thọ diệt nên ái diệt.’ ",
  "dn14:2.20.21": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ như sau: ",
  "dn14:2.20.22": "‘Khi cái gì không có thì thọ không có, do sự diệt của cái gì mà thọ diệt?’ ",
  "dn14:2.20.23": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ: ",
  "dn14:2.20.24": "‘Khi xúc không có thì thọ không có, do xúc diệt nên thọ diệt.’ ",
  "dn14:2.20.25": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ như sau: ",
  "dn14:2.20.26": "‘Khi cái gì không có thì xúc không có, do sự diệt của cái gì mà xúc diệt?’ ",
  "dn14:2.20.27": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ: ",
  "dn14:2.20.28": "‘Khi sáu xứ không có thì xúc không có, do sáu xứ diệt nên xúc diệt.’ ",
  "dn14:2.20.29": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ như sau: ",
  "dn14:2.20.30": "‘Khi cái gì không có thì sáu xứ không có, do sự diệt của cái gì mà sáu xứ diệt?’ ",
  "dn14:2.20.31": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ: ",
  "dn14:2.20.32": "‘Khi danh sắc không có thì sáu xứ không có, do danh sắc diệt nên sáu xứ diệt.’ ",
  "dn14:2.20.33": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ như sau: ",
  "dn14:2.20.34": "‘Khi cái gì không có thì danh sắc không có, do sự diệt của cái gì mà danh sắc diệt?’ ",
  "dn14:2.20.35": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ: ",
  "dn14:2.20.36": "‘Khi thức không có thì danh sắc không có, do thức diệt nên danh sắc diệt.’ ",
  "dn14:2.20.37": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ như sau: ",
  "dn14:2.20.38": "‘Khi cái gì không có thì thức không có, do sự diệt của cái gì mà thức diệt?’ ",
  "dn14:2.20.39": "Rồi này các Tỳ-kheo, do tác ý như lý, Bồ-tát Vipassī có sự chứng ngộ bằng trí tuệ: ",
  "dn14:2.20.40": "‘Khi danh sắc không có thì thức không có, do danh sắc diệt nên thức diệt.’ ",
  "dn14:2.21.1": "Rồi này các Tỳ-kheo, Bồ-tát Vipassī nghĩ như sau: ",
  "dn14:2.21.2": "‘Con đường này đưa đến giác ngộ đã được ta chứng đạt, tức là—",
  "dn14:2.21.3": "do danh sắc diệt nên thức diệt, do thức diệt nên danh sắc diệt, do danh sắc diệt nên sáu xứ diệt, do sáu xứ diệt nên xúc diệt, do xúc diệt nên thọ diệt, do thọ diệt nên ái diệt, do ái diệt nên thủ diệt, do thủ diệt nên hữu diệt, do hữu diệt nên sinh diệt, do sinh diệt nên già chết, sầu, bi, khổ, ưu, não đều diệt. ",
  "dn14:2.21.4": "Như vậy là sự diệt của toàn bộ khối khổ này.’ ",
  "dn14:2.21.5": "Này các Tỳ-kheo, khi nói: ‘Diệt, diệt’, thì đối với Bồ-tát Vipassī, nơi các pháp trước đây chưa từng được nghe, con mắt khởi lên, trí khởi lên, tuệ khởi lên, minh khởi lên, ánh sáng khởi lên. ",
  "dn14:2.22.1": "Rồi này các Tỳ-kheo, sau một thời gian, Bồ-tát Vipassī an trú quán sự sinh diệt trong năm thủ uẩn: ",
  "dn14:2.22.2": "‘Đây là sắc, đây là sự sinh khởi của sắc, đây là sự đoạn diệt của sắc; ",
  "dn14:2.22.3": "đây là thọ, đây là sự sinh khởi của thọ, đây là sự đoạn diệt của thọ; ",
  "dn14:2.22.4": "đây là tưởng, đây là sự sinh khởi của tưởng, đây là sự đoạn diệt của tưởng; ",
  "dn14:2.22.5": "đây là các hành, đây là sự sinh khởi của các hành, đây là sự đoạn diệt của các hành; ",
  "dn14:2.22.6": "đây là thức, đây là sự sinh khởi của thức, đây là sự đoạn diệt của thức.’ ",
  "dn14:2.22.7": "Trong khi an trú quán sự sinh diệt trong năm thủ uẩn như vậy, chẳng bao lâu tâm ngài được giải thoát khỏi các lậu hoặc do không còn chấp thủ. ",
  "dn14:2.22.8": "Phần tụng đọc thứ hai. ",
  "dn14:3.1.0": "12. Câu chuyện thỉnh cầu của Phạm thiên ",
  "dn14:3.1.1": "Rồi này các Tỳ-kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác nghĩ như sau: ",
  "dn14:3.1.2": "‘Hay là ta thuyết pháp chăng?’ ",
  "dn14:3.1.3": "Rồi này các Tỳ-kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác nghĩ như sau: ",
  "dn14:3.1.4": "‘Pháp này do ta chứng đạt thật sâu xa, khó thấy, khó hiểu, tịch tịnh, thù thắng, vượt ngoài suy luận, vi tế, chỉ người trí mới tự mình chứng biết. ",
  "dn14:3.1.5": "Nhưng chúng sinh này ưa thích chỗ nương tựa, vui thích chỗ nương tựa, hoan hỷ chỗ nương tựa. ",
  "dn14:3.1.6": "Đối với chúng sinh ưa thích chỗ nương tựa, vui thích chỗ nương tựa, hoan hỷ chỗ nương tựa như vậy, trạng thái này thật khó thấy, tức là tính duyên khởi do cái này có nên cái kia có. ",
  "dn14:3.1.7": "Và trạng thái này cũng khó thấy, tức là sự lắng dịu của tất cả hành, sự từ bỏ mọi y cứ, sự đoạn tận ái, ly tham, diệt, Niết-bàn. ",
  "dn14:3.1.8": "Nếu ta thuyết pháp mà người khác không hiểu ta, điều ấy sẽ là mệt nhọc cho ta, điều ấy sẽ là phiền lụy cho ta.’ ",
  "dn14:3.2.1": "Lại nữa, này các Tỳ-kheo, những bài kệ chưa từng được nghe trước đây hiện ra với Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác: ",
  "dn14:3.2.2": "‘Khó khăn lắm ta mới chứng đạt, ",
  "dn14:3.2.3": "nay không nên vội tuyên bày; ",
  "dn14:3.2.4": "với những kẻ bị tham sân chi phối, ",
  "dn14:3.2.5": "pháp này không dễ được giác hiểu. ",
  "dn14:3.2.6": "Đi ngược dòng, vi tế, ",
  "dn14:3.2.7": "sâu xa, khó thấy, nhỏ nhiệm; ",
  "dn14:3.2.8": "những ai đắm nhiễm tham ái không thể thấy, ",
  "dn14:3.2.9": "bị khối tối tăm bao phủ.’ ",
  "dn14:3.2.10": "Như vậy, này các Tỳ-kheo, khi suy xét như thế, tâm của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác nghiêng về sự an tịnh, không hướng đến thuyết pháp. ",
  "dn14:3.2.11": "Rồi này các Tỳ-kheo, một vị Đại Phạm thiên biết được tâm tư suy nghĩ trong tâm của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, liền nghĩ rằng: ",
  "dn14:3.2.12": "‘Than ôi, thế gian sắp mất rồi, than ôi, thế gian sắp tiêu vong rồi, vì tâm của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác nghiêng về sự an tịnh, không hướng đến thuyết pháp.’ ",
  "dn14:3.2.13": "Rồi này các Tỳ-kheo, vị Đại Phạm thiên ấy, như người lực sĩ co cánh tay đang duỗi ra hay duỗi cánh tay đang co lại, cũng vậy, biến mất khỏi cõi Phạm thiên và hiện ra trước mặt Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn14:3.3.1": "Rồi này các Tỳ-kheo, vị Đại Phạm thiên ấy vắt thượng y qua một bên vai, quỳ gối phải xuống đất, chắp tay hướng về Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, và thưa rằng: ",
  "dn14:3.3.2": "‘Bạch Thế Tôn, xin Thế Tôn thuyết pháp, xin bậc Thiện Thệ thuyết pháp, ",
  "dn14:3.3.3": "có những chúng sinh thuộc hạng ít bụi trong mắt; nếu không được nghe pháp, họ sẽ bị sa sút, ",
  "dn14:3.3.4": "sẽ có những người hiểu được pháp.’ ",
  "dn14:3.4.1": "Khi được nói vậy, này các Tỳ-kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác nói với vị Đại Phạm thiên ấy rằng: ",
  "dn14:3.4.2": "‘Này Phạm thiên, chính ta cũng đã nghĩ như sau: ",
  "dn14:3.4.3": "“Hay là ta thuyết pháp chăng?” ",
  "dn14:3.4.4": "Này Phạm thiên, rồi ta nghĩ như sau: ",
  "dn14:3.4.5": "“Pháp này do ta chứng đạt thật sâu xa, khó thấy, khó hiểu, tịch tịnh, thù thắng, vượt ngoài suy luận, vi tế, chỉ người trí mới tự mình chứng biết. ",
  "dn14:3.4.6": "Nhưng chúng sinh này ưa thích chỗ nương tựa, vui thích chỗ nương tựa, hoan hỷ chỗ nương tựa. ",
  "dn14:3.4.7": "Đối với chúng sinh ưa thích chỗ nương tựa, vui thích chỗ nương tựa, hoan hỷ chỗ nương tựa như vậy, trạng thái này thật khó thấy, tức là tính duyên khởi do cái này có nên cái kia có. ",
  "dn14:3.4.8": "Và trạng thái này cũng khó thấy, tức là sự lắng dịu của tất cả hành, sự từ bỏ mọi y cứ, sự đoạn tận ái, ly tham, diệt, Niết-bàn. ",
  "dn14:3.4.9": "Nếu ta thuyết pháp mà người khác không hiểu ta, điều ấy sẽ là mệt nhọc cho ta, điều ấy sẽ là phiền lụy cho ta.” ",
  "dn14:3.4.10": "Lại nữa, này Phạm thiên, những bài kệ chưa từng được nghe trước đây hiện ra với ta: ",
  "dn14:3.4.11": "“Khó khăn lắm ta mới chứng đạt, ",
  "dn14:3.4.12": "nay không nên vội tuyên bày; ",
  "dn14:3.4.13": "với những kẻ bị tham sân chi phối, ",
  "dn14:3.4.14": "pháp này không dễ được giác hiểu. ",
  "dn14:3.4.15": "Đi ngược dòng, vi tế, ",
  "dn14:3.4.16": "sâu xa, khó thấy, nhỏ nhiệm; ",
  "dn14:3.4.17": "những ai đắm nhiễm tham ái không thể thấy, ",
  "dn14:3.4.18": "bị khối tối tăm bao phủ.” ",
  "dn14:3.4.19": "Như vậy, này Phạm thiên, khi suy xét như thế, tâm ta nghiêng về sự an tịnh, không hướng đến thuyết pháp.’ ",
  "dn14:3.5.1": "Lần thứ hai, này các Tỳ-kheo, vị Đại Phạm thiên ấy … ",
  "dn14:3.5.2": "lần thứ ba, này các Tỳ-kheo, vị Đại Phạm thiên ấy thưa với Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác rằng: ",
  "dn14:3.5.3": "‘Bạch Thế Tôn, xin Thế Tôn thuyết pháp, xin bậc Thiện Thệ thuyết pháp, có những chúng sinh thuộc hạng ít bụi trong mắt, nếu không được nghe pháp, họ sẽ bị sa sút, sẽ có những người hiểu được pháp.’ ",
  "dn14:3.6.1": "Rồi này các Tỳ-kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, sau khi biết lời thỉnh cầu của Phạm thiên và do lòng thương tưởng chúng sinh, đã dùng Phật nhãn quán sát thế gian. ",
  "dn14:3.6.2": "Này các Tỳ-kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, khi dùng Phật nhãn quán sát thế gian, thấy các chúng sinh có ít bụi trong mắt, nhiều bụi trong mắt, căn tánh sắc bén, căn tánh chậm lụt, có tướng tốt, có tướng xấu, dễ dạy, khó dạy; một số sống thấy sợ hãi đối với lỗi lầm và đời sau, một số không sống thấy sợ hãi đối với lỗi lầm và đời sau. ",
  "dn14:3.6.3": "Ví như trong hồ sen xanh, hồ sen hồng hay hồ sen trắng, có một số hoa sen xanh, sen hồng hay sen trắng sinh trong nước, lớn lên trong nước, còn chìm trong nước, được nước nuôi dưỡng. Có một số hoa sen xanh, sen hồng hay sen trắng sinh trong nước, lớn lên trong nước, đứng ngang mặt nước. Có một số hoa sen xanh, sen hồng hay sen trắng sinh trong nước, lớn lên trong nước, vươn lên khỏi nước, không bị nước làm nhiễm ướt. ",
  "dn14:3.6.4": "Cũng vậy, này các Tỳ-kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, khi dùng Phật nhãn quán sát thế gian, thấy các chúng sinh có ít bụi trong mắt, nhiều bụi trong mắt, căn tánh sắc bén, căn tánh chậm lụt, có tướng tốt, có tướng xấu, dễ dạy, khó dạy; một số sống thấy sợ hãi đối với lỗi lầm và đời sau, một số không sống thấy sợ hãi đối với lỗi lầm và đời sau. ",
  "dn14:3.7.1": "Rồi này các Tỳ-kheo, vị Đại Phạm thiên ấy, sau khi biết được tâm tư suy nghĩ trong tâm của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã nói với Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác bằng những bài kệ: ",
  "dn14:3.7.2": "‘Như người đứng trên đỉnh núi đá, ",
  "dn14:3.7.3": "có thể nhìn thấy quần chúng khắp bốn phía; ",
  "dn14:3.7.4": "cũng vậy, bậc đại trí, pháp thân viên mãn, ",
  "dn14:3.7.5": "Hãy lên lầu cao, bậc có mắt nhìn khắp mọi phía;",
  "dn14:3.7.6": "không sầu giữa quần chúng đang chìm trong sầu khổ,",
  "dn14:3.7.7": "hãy nhìn xem dân chúng bị sinh già chế ngự.",
  "dn14:3.7.8": "Hãy đứng dậy, bậc anh hùng, bậc chiến thắng trận chiến,",
  "dn14:3.7.9": "vị dẫn đường, không mắc nợ, hãy du hành trong đời;",
  "dn14:3.7.10": "xin Thế Tôn thuyết pháp,",
  "dn14:3.7.11": "sẽ có những người hiểu biết.”",
  "dn14:3.7.12": "Rồi này các Tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã đáp lại vị Đại Phạm thiên ấy bằng bài kệ:",
  "dn14:3.7.13": "“Cửa bất tử đã mở ra cho họ,",
  "dn14:3.7.14": "ai có tai hãy buông bỏ lòng tin mù quáng;",
  "dn14:3.7.15": "vì nghĩ đến sự tổn hại nên Ta đã không nói",
  "dn14:3.7.16": "pháp vi diệu, thâm diệu giữa loài người, này Phạm thiên.”",
  "dn14:3.7.17": "Rồi này các Tỳ-kheo, vị Đại Phạm thiên ấy nghĩ: “Ta đã được đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, cho phép thuyết pháp rồi”, đảnh lễ đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đi nhiễu bên phải rồi biến mất ngay tại chỗ.",
  "dn14:3.8.0": "13. Đôi thượng thủ đệ tử",
  "dn14:3.8.1": "Rồi này các Tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, nghĩ rằng:",
  "dn14:3.8.2": "“Ta nên thuyết pháp đầu tiên cho ai đây,",
  "dn14:3.8.3": "ai sẽ mau chóng hiểu được pháp này?”",
  "dn14:3.8.4": "Rồi này các Tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, nghĩ rằng:",
  "dn14:3.8.5": "“Hoàng tử Khaṇḍa và con trai vị tế sư là Tissa đang cư trú tại kinh đô Bandhumatī; họ là những người hiền trí, thông đạt, sáng suốt, từ lâu thuộc hạng ít bụi trong mắt.",
  "dn14:3.8.6": "Hay là Ta sẽ thuyết pháp đầu tiên cho hoàng tử Khaṇḍa và con trai vị tế sư Tissa; họ sẽ mau chóng hiểu được pháp này.”",
  "dn14:3.9.1": "Rồi này các Tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, như người lực sĩ co cánh tay lại rồi duỗi ra, hay duỗi ra rồi co lại; cũng vậy, Ngài biến mất dưới cội bồ-đề và hiện ra tại vườn nai Khema ở kinh đô Bandhumatī.",
  "dn14:3.9.2": "Rồi này các Tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, gọi người giữ vườn:",
  "dn14:3.9.3": "“Này bạn giữ vườn, hãy đi vào kinh đô Bandhumatī và nói với hoàng tử Khaṇḍa cùng con trai vị tế sư Tissa như sau:",
  "dn14:3.9.4": "‘Bạch ngài, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã đến kinh đô Bandhumatī, hiện đang ở tại vườn nai Khema; Ngài muốn gặp các ngài.’”",
  "dn14:3.9.5": "“Thưa vâng, bạch Thế Tôn”, này các Tỳ-kheo, người giữ vườn vâng lời đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, rồi đi vào kinh đô Bandhumatī và nói với hoàng tử Khaṇḍa cùng con trai vị tế sư Tissa rằng:",
  "dn14:3.9.6": "“Bạch ngài, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã đến kinh đô Bandhumatī, hiện đang ở tại vườn nai Khema; Ngài muốn gặp các ngài.”",
  "dn14:3.10.1": "Rồi này các Tỳ-kheo, hoàng tử Khaṇḍa và con trai vị tế sư Tissa cho thắng những cỗ xe tốt đẹp, lên những cỗ xe tốt đẹp ấy, rồi từ kinh đô Bandhumatī đi ra bằng những cỗ xe tốt đẹp, hướng đến vườn nai Khema.",
  "dn14:3.10.2": "Đi xe đến chỗ nào còn đi được, họ xuống xe rồi đi bộ đến chỗ đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác. Đến nơi, họ đảnh lễ đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, rồi ngồi xuống một bên.",
  "dn14:3.11.1": "Đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã thuyết cho họ bài pháp tuần tự, như là:",
  "dn14:3.11.2": "nói về bố thí, nói về giới, nói về cõi trời, chỉ rõ sự nguy hại, thấp hèn, ô nhiễm của các dục, và lợi ích của xuất ly.",
  "dn14:3.11.3": "Khi Thế Tôn biết tâm họ đã sẵn sàng, mềm mại, không còn chướng ngại, hoan hỷ, trong sáng, thì Ngài thuyết pháp đặc biệt của chư Phật:",
  "dn14:3.11.4": "khổ, tập, diệt, đạo.",
  "dn14:3.11.5": "Ví như tấm vải sạch, không còn vết đen, có thể nhận màu nhuộm một cách hoàn toàn;",
  "dn14:3.11.6": "cũng vậy, ngay tại chỗ ngồi ấy, pháp nhãn không bụi, không nhơ đã sinh khởi nơi hoàng tử Khaṇḍa và con trai vị tế sư Tissa:",
  "dn14:3.11.7": "“Bất cứ pháp gì có tính sinh khởi, tất cả đều có tính diệt.”",
  "dn14:3.12.1": "Họ đã thấy pháp, chứng pháp, biết pháp, thâm nhập pháp, vượt qua nghi ngờ, dứt mọi phân vân, đạt được vô úy, không còn do người khác dẫn dắt trong giáo pháp của bậc Đạo Sư, liền bạch đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác rằng:",
  "dn14:3.12.2": "“Thật vi diệu, bạch Thế Tôn, thật vi diệu, bạch Thế Tôn.",
  "dn14:3.12.3": "Ví như, bạch Thế Tôn, dựng đứng lại vật bị úp xuống, mở ra vật bị che kín, chỉ đường cho người lạc lối, đem đèn vào chỗ tối để người có mắt thấy được các sắc; cũng vậy, Chánh pháp đã được Thế Tôn dùng nhiều phương tiện trình bày.",
  "dn14:3.12.4": "Chúng con xin quy y Thế Tôn và quy y Pháp.",
  "dn14:3.12.5": "Mong chúng con được xuất gia với Thế Tôn, được thọ đại giới.”",
  "dn14:3.13.1": "Này các Tỳ-kheo, hoàng tử Khaṇḍa và con trai vị tế sư Tissa đã được xuất gia, được thọ đại giới với đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác.",
  "dn14:3.13.2": "Đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã dùng pháp thoại chỉ dạy, khích lệ, làm phấn chấn, làm hoan hỷ họ;",
  "dn14:3.13.3": "Ngài chỉ rõ sự nguy hại, thấp hèn, ô nhiễm của các hành và lợi ích của Niết-bàn.",
  "dn14:3.13.4": "Trong khi được đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, chỉ dạy, khích lệ, làm phấn chấn, làm hoan hỷ bằng pháp thoại như vậy, chẳng bao lâu tâm họ được giải thoát khỏi các lậu hoặc do không còn chấp thủ.",
  "dn14:3.14.0": "14. Sự xuất gia của đại chúng",
  "dn14:3.14.1": "Này các Tỳ-kheo, đại chúng ở kinh đô Bandhumatī gồm tám mươi bốn ngàn người đã nghe rằng:",
  "dn14:3.14.2": "“Nghe nói đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã đến kinh đô Bandhumatī, hiện đang ở tại vườn nai Khema.",
  "dn14:3.14.3": "Nghe nói hoàng tử Khaṇḍa và con trai vị tế sư Tissa đã cạo bỏ râu tóc, đắp y ca-sa, từ bỏ gia đình, xuất gia sống không gia đình với đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác.”",
  "dn14:3.14.4": "Nghe vậy, họ nghĩ rằng:",
  "dn14:3.14.5": "“Chắc hẳn pháp luật ấy không phải tầm thường, sự xuất gia ấy không phải tầm thường, vì ở đó hoàng tử Khaṇḍa và con trai vị tế sư Tissa đã cạo bỏ râu tóc, đắp y ca-sa, từ bỏ gia đình, xuất gia sống không gia đình.",
  "dn1414:3.14.6": "Nếu hoàng tử Khaṇḍa và con trai vị tế sư Tissa cạo bỏ râu tóc, đắp y ca-sa, từ bỏ gia đình, xuất gia sống không gia đình, huống nữa là chúng ta.”",
  "dn14:3.14.7": "Rồi này các Tỳ-kheo, đại chúng ấy gồm tám mươi bốn ngàn người đi ra khỏi kinh đô Bandhumatī, đến vườn nai Khema, đến chỗ đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác. Đến nơi, họ đảnh lễ đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, rồi ngồi xuống một bên.",
  "dn14:3.15.1": "Đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã thuyết cho họ bài pháp tuần tự.",
  "dn14:3.15.2": "Đó là nói về bố thí, nói về giới, nói về cõi trời, chỉ rõ sự nguy hại, thấp hèn, ô nhiễm của các dục, và lợi ích của xuất ly.",
  "dn14:3.15.3": "Khi Thế Tôn biết tâm họ đã sẵn sàng, mềm mại, không còn chướng ngại, hoan hỷ, trong sáng, thì Ngài thuyết pháp đặc biệt của chư Phật:",
  "dn14:3.15.4": "khổ, tập, diệt, đạo.",
  "dn14:3.15.5": "Ví như tấm vải sạch, không còn vết đen, có thể nhận màu nhuộm một cách hoàn toàn;",
  "dn14:3.15.6": "cũng vậy, ngay tại chỗ ngồi ấy, pháp nhãn không bụi, không nhơ đã sinh khởi nơi tám mươi bốn ngàn người ấy:",
  "dn14:3.15.7": "“Bất cứ pháp gì có tính sinh khởi, tất cả đều có tính diệt.”",
  "dn14:3.16.1": "Họ đã thấy pháp, chứng pháp, biết pháp, thâm nhập pháp, vượt qua nghi ngờ, dứt mọi phân vân, đạt được vô úy, không còn do người khác dẫn dắt trong giáo pháp của bậc Đạo Sư, liền bạch đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác rằng:",
  "dn14:3.16.2": "“Thật vi diệu, bạch Thế Tôn, thật vi diệu, bạch Thế Tôn.",
  "dn14:3.16.3": "Ví như, bạch Thế Tôn, dựng đứng lại vật bị úp xuống, mở ra vật bị che kín, chỉ đường cho người lạc lối, đem đèn vào chỗ tối để người có mắt thấy được các sắc; cũng vậy, Chánh pháp đã được Thế Tôn dùng nhiều phương tiện trình bày.",
  "dn14:3.16.4": "Chúng con xin quy y Thế Tôn, quy y Pháp và quy y Tỳ-kheo Tăng.",
  "dn14:3.16.5": "Mong chúng con được xuất gia với Thế Tôn, được thọ đại giới.”",
  "dn14:3.17.1": "Này các Tỳ-kheo, tám mươi bốn ngàn người ấy đã được xuất gia, được thọ đại giới với đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác.",
  "dn14:3.17.2": "Đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã dùng pháp thoại chỉ dạy, khích lệ, làm phấn chấn, làm hoan hỷ họ;",
  "dn14:3.17.3": "Ngài chỉ rõ sự nguy hại, thấp hèn, ô nhiễm của các hành và lợi ích của Niết-bàn.",
  "dn14:3.17.4": "Trong khi được đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, chỉ dạy, khích lệ, làm phấn chấn, làm hoan hỷ bằng pháp thoại như vậy, chẳng bao lâu tâm họ được giải thoát khỏi các lậu hoặc do không còn chấp thủ.",
  "dn14:3.18.0": "15. Sự chứng ngộ pháp của những người xuất gia trước",
  "dn14:3.18.1": "Này các Tỳ-kheo, tám mươi bốn ngàn người đã xuất gia trước đó nghe rằng:",
  "dn14:3.18.2": "“Nghe nói đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã đến kinh đô Bandhumatī, hiện đang ở tại vườn nai Khema, và đang thuyết pháp.”",
  "dn14:3.18.3": "Rồi này các Tỳ-kheo, tám mươi bốn ngàn người đã xuất gia ấy đi đến kinh đô Bandhumatī, đến vườn nai Khema, đến chỗ đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác. Đến nơi, họ đảnh lễ đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, rồi ngồi xuống một bên.",
  "dn14:3.19.1": "Đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã thuyết cho họ bài pháp tuần tự.",
  "dn14:3.19.2": "Đó là nói về bố thí, nói về giới, nói về cõi trời, chỉ rõ sự nguy hại, thấp hèn, ô nhiễm của các dục, và lợi ích của xuất ly.",
  "dn14:3.19.3": "Khi Thế Tôn biết tâm họ đã sẵn sàng, mềm mại, không còn chướng ngại, hoan hỷ, trong sáng, thì Ngài thuyết pháp đặc biệt của chư Phật:",
  "dn14:3.19.4": "khổ, tập, diệt, đạo.",
  "dn14:3.19.5": "Ví như tấm vải sạch, không còn vết đen, có thể nhận màu nhuộm một cách hoàn toàn;",
  "dn14:3.19.6": "cũng vậy, ngay tại chỗ ngồi ấy, pháp nhãn không bụi, không nhơ đã sinh khởi nơi tám mươi bốn ngàn người xuất gia ấy:",
  "dn14:3.19.7": "“Bất cứ pháp gì có tính sinh khởi, tất cả đều có tính diệt.”",
  "dn14:3.20.1": "Họ đã thấy pháp, chứng pháp, biết pháp, thâm nhập pháp, vượt qua nghi ngờ, dứt mọi phân vân, đạt được vô úy, không còn do người khác dẫn dắt trong giáo pháp của bậc Đạo Sư, liền bạch đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác rằng:",
  "dn14:3.20.2": "“Thật vi diệu, bạch Thế Tôn, thật vi diệu, bạch Thế Tôn.",
  "dn14:3.20.3": "Ví như, bạch Thế Tôn, dựng đứng lại vật bị úp xuống, mở ra vật bị che kín, chỉ đường cho người lạc lối, đem đèn vào chỗ tối để người có mắt thấy được các sắc; cũng vậy, Chánh pháp đã được Thế Tôn dùng nhiều phương tiện trình bày.",
  "dn14:3.20.4": "Chúng con xin quy y Thế Tôn, quy y Pháp và quy y Tỳ-kheo Tăng.",
  "dn14:3.20.5": "Mong chúng con được xuất gia với Thế Tôn, được thọ đại giới.”",
  "dn14:3.21.1": "Này các Tỳ-kheo, tám mươi bốn ngàn người xuất gia ấy đã được xuất gia, được thọ đại giới với đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác.",
  "dn14:3.21.2": "Đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã dùng pháp thoại chỉ dạy, khích lệ, làm phấn chấn, làm hoan hỷ họ;",
  "dn14:3.21.3": "Ngài chỉ rõ sự nguy hại, thấp hèn, ô nhiễm của các hành và lợi ích của Niết-bàn.",
  "dn14:3.21.4": "Trong khi được đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, chỉ dạy, khích lệ, làm phấn chấn, làm hoan hỷ bằng pháp thoại như vậy, chẳng bao lâu tâm họ được giải thoát khỏi các lậu hoặc do không còn chấp thủ.",
  "dn14:3.22.0": "16. Cho phép du hành",
  "dn14:3.22.1": "Này các Tỳ-kheo, vào thời ấy, đại Tỳ-kheo Tăng cư trú tại kinh đô Bandhumatī gồm sáu triệu tám trăm ngàn Tỳ-kheo.",
  "dn14:3.22.2": "Rồi này các Tỳ-kheo, khi đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, sống viễn ly, độc cư, thì ý nghĩ này khởi lên trong tâm Ngài:",
  "dn14:3.22.3": "“Hiện nay đại Tỳ-kheo Tăng cư trú tại kinh đô Bandhumatī gồm sáu triệu tám trăm ngàn Tỳ-kheo, hay là Ta cho phép các Tỳ-kheo:",
  "dn14:3.22.4": "‘Này các Tỳ-kheo, hãy đi du hành vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người;",
  "dn14:3.22.5": "chớ hai người cùng đi một đường;",
  "dn14:3.22.6": "này các Tỳ-kheo, hãy thuyết pháp tốt đẹp ở đoạn đầu, tốt đẹp ở đoạn giữa, tốt đẹp ở đoạn cuối, có nghĩa, có văn, trình bày đầy đủ, trọn vẹn, thanh tịnh phạm hạnh.",
  "dn14:3.22.7": "Có những chúng sinh ít bụi trong mắt, vì không được nghe pháp nên bị tổn giảm,",
  "dn14:3.22.8": "sẽ có những người hiểu được pháp.",
  "dn14:3.22.9": "Và sau mỗi sáu năm, phải trở về kinh đô Bandhumatī để tụng đọc giới bổn.’”",
  "dn14:3.23.1": "Rồi này các Tỳ-kheo, một vị Đại Phạm thiên, biết được tâm tư suy nghĩ trong tâm của đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, cũng như người lực sĩ co cánh tay lại rồi duỗi ra, hay duỗi ra rồi co lại; cũng vậy, vị ấy biến mất khỏi cõi Phạm thiên và hiện ra trước mặt đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác.",
  "dn14:3.23.2": "Rồi này các Tỳ-kheo, vị Đại Phạm thiên ấy đắp thượng y một bên vai, chắp tay hướng về đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, và thưa rằng:",
  "dn14:3.23.3": "‘Đúng vậy, bạch Thế Tôn, đúng vậy, bạch Thiện Thệ.",
  "dn14:3.23.4": "Bạch Thế Tôn, hiện nay đại chúng Tỳ-kheo đang cư trú tại kinh đô Bandhumatī gồm sáu mươi tám vạn Tỳ-kheo, xin Thế Tôn cho phép các Tỳ-kheo:",
  "dn14:3.23.5": "“Này các Tỳ-kheo, hãy du hành vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người;",
  "dn14:3.23.6": "chớ hai người đi cùng một đường;",
  "dn14:3.23.7": "này các Tỳ-kheo, hãy thuyết pháp tốt đẹp ở đoạn đầu, tốt đẹp ở đoạn giữa, tốt đẹp ở đoạn cuối, có nghĩa, có văn, trình bày phạm hạnh hoàn toàn đầy đủ, thanh tịnh.",
  "dn14:3.23.8": "Có những chúng sinh ít bụi trong mắt, do không được nghe pháp nên bị tổn thất; họ sẽ là những người hiểu được pháp.”",
  "dn14:3.23.9": "Và nữa, bạch Thế Tôn, chúng con sẽ làm sao để các Tỳ-kheo cứ sau mỗi sáu năm sẽ trở về kinh đô Bandhumatī để tụng đọc giới bổn.’",
  "dn14:3.23.10": "Này các Tỳ-kheo, vị Đại Phạm thiên ấy đã nói như vậy.",
  "dn14:3.23.11": "Nói xong, sau khi đảnh lễ đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đi nhiễu bên phải rồi biến mất ngay tại chỗ ấy.",
  "dn14:3.24.1": "Rồi này các Tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, vào buổi chiều, sau khi xuất khỏi chỗ tĩnh cư, gọi các Tỳ-kheo:",
  "dn14:3.24.2": "‘Này các Tỳ-kheo, khi Ta sống viễn ly, an trú độc cư, tâm Ta khởi lên suy nghĩ này:",
  "dn14:3.24.3": "“Hiện nay đại chúng Tỳ-kheo đang cư trú tại kinh đô Bandhumatī gồm sáu mươi tám vạn Tỳ-kheo.",
  "dn14:3.24.4": "Hay là Ta cho phép các Tỳ-kheo—",
  "dn14:3.24.5": "này các Tỳ-kheo, hãy du hành vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người;",
  "dn14:3.24.6": "chớ hai người đi cùng một đường;",
  "dn14:3.24.7": "này các Tỳ-kheo, hãy thuyết pháp tốt đẹp ở đoạn đầu, tốt đẹp ở đoạn giữa, tốt đẹp ở đoạn cuối, có nghĩa, có văn, trình bày phạm hạnh hoàn toàn đầy đủ, thanh tịnh.",
  "dn14:3.24.8": "Có những chúng sinh ít bụi trong mắt, do không được nghe pháp nên bị tổn thất; họ sẽ là những người hiểu được pháp.",
  "dn14:3.24.9": "Và cứ sau mỗi sáu năm thì phải trở về kinh đô Bandhumatī để tụng đọc giới bổn.”’",
  "dn14:3.25.1": "Rồi này các Tỳ-kheo, một vị Đại Phạm thiên khác, biết được ý nghĩ trong tâm Ta bằng tâm mình, cũng như một người lực lưỡng co cánh tay lại hay duỗi cánh tay ra; cũng vậy, vị ấy biến mất khỏi cõi Phạm thiên và hiện ra trước mặt Ta.",
  "dn14:3.25.2": "Rồi này các Tỳ-kheo, vị Đại Phạm thiên ấy vắt thượng y qua một bên vai, chắp tay hướng về phía Ta và nói với Ta như sau:",
  "dn14:3.25.3": "‘Đúng vậy, bạch Thế Tôn, đúng vậy, bạch Thiện Thệ.",
  "dn14:3.25.4": "Bạch Thế Tôn, hiện nay đại chúng Tỳ-kheo đang cư trú tại kinh đô Bandhumatī gồm sáu mươi tám vạn Tỳ-kheo.",
  "dn14:3.25.5": "Xin Thế Tôn cho phép các Tỳ-kheo—",
  "dn14:3.25.6": "này các Tỳ-kheo, hãy du hành vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người;",
  "dn14:3.25.7": "chớ hai người đi cùng một đường;",
  "dn14:3.25.8": "này các Tỳ-kheo, hãy thuyết pháp …",
  "dn14:3.25.9": "có những chúng sinh ít bụi trong mắt, do không được nghe pháp nên bị tổn thất; họ sẽ là những người hiểu được pháp.",
  "dn14:3.25.10": "Và nữa, bạch Thế Tôn, chúng con sẽ làm sao để các Tỳ-kheo cứ sau mỗi sáu năm sẽ trở về kinh đô Bandhumatī để tụng đọc giới bổn.’",
  "dn14:3.25.11": "Này các Tỳ-kheo, vị Đại Phạm thiên ấy đã nói như vậy.",
  "dn14:3.25.12": "Nói xong, sau khi đảnh lễ Ta, đi nhiễu bên phải rồi biến mất ngay tại chỗ ấy.",
  "dn14:3.26.1": "‘Này các Tỳ-kheo, Ta cho phép: hãy du hành vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người;",
  "dn14:3.26.2": "chớ hai người đi cùng một đường;",
  "dn14:3.26.3": "này các Tỳ-kheo, hãy thuyết pháp tốt đẹp ở đoạn đầu, tốt đẹp ở đoạn giữa, tốt đẹp ở đoạn cuối, có nghĩa, có văn, trình bày phạm hạnh hoàn toàn đầy đủ, thanh tịnh.",
  "dn14:3.26.4": "Có những chúng sinh ít bụi trong mắt, do không được nghe pháp nên bị tổn thất,",
  "dn14:3.26.5": "họ sẽ là những người hiểu được pháp.",
  "dn14:3.26.6": "Và nữa, này các Tỳ-kheo, cứ sau mỗi sáu năm thì phải trở về kinh đô Bandhumatī để tụng đọc giới bổn.’",
  "dn14:3.26.7": "Rồi này các Tỳ-kheo, phần lớn các Tỳ-kheo chỉ trong một ngày đã lên đường du hành các xứ.",
  "dn14:3.27.1": "Vào thời ấy, trong cõi Jambudīpa có tám mươi bốn ngàn trú xứ.",
  "dn14:3.27.2": "Khi một năm đã trôi qua, chư thiên cất tiếng loan báo:",
  "dn14:3.27.3": "‘Này chư hiền, một năm đã trôi qua;",
  "dn14:3.27.4": "nay còn lại năm năm;",
  "dn14:3.27.5": "sau năm năm phải trở về kinh đô Bandhumatī để tụng đọc giới bổn.’",
  "dn14:3.27.6": "Khi hai năm đã trôi qua …",
  "dn14:3.27.7": "khi ba năm đã trôi qua …",
  "dn14:3.27.8": "khi bốn năm đã trôi qua …",
  "dn14:3.27.9": "khi năm năm đã trôi qua, chư thiên cất tiếng loan báo:",
  "dn14:3.27.10": "‘Này chư hiền, năm năm đã trôi qua;",
  "dn14:3.27.11": "nay còn lại một năm;",
  "dn14:3.27.12": "sau một năm phải trở về kinh đô Bandhumatī để tụng đọc giới bổn.’",
  "dn14:3.27.13": "Khi sáu năm đã trôi qua, chư thiên cất tiếng loan báo:",
  "dn14:3.27.14": "‘Này chư hiền, sáu năm đã trôi qua,",
  "dn14:3.27.15": "nay là lúc trở về kinh đô Bandhumatī để tụng đọc giới bổn.’",
  "dn14:3.27.16": "Rồi này các Tỳ-kheo, trong số các Tỳ-kheo ấy, có vị nhờ thần lực của chính mình, có vị nhờ thần lực của chư thiên, chỉ trong một ngày đã trở về kinh đô Bandhumatī để tụng đọc giới bổn.",
  "dn14:3.28.1": "Tại đó, này các Tỳ-kheo, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã tụng đọc giới bổn giữa chúng Tỳ-kheo như sau:",
  "dn14:3.28.2": "‘Nhẫn nhục là khổ hạnh tối thượng,",
  "dn14:3.28.3": "Niết-bàn là tối thượng, chư Phật nói vậy;",
  "dn14:3.28.4": "Người xuất gia không phải là kẻ hại người khác,",
  "dn14:3.28.5": "Người sa-môn không phải là kẻ não hại người khác.",
  "dn14:3.28.6": "Không làm mọi điều ác,",
  "dn14:3.28.7": "thành tựu các điều lành;",
  "dn14:3.28.8": "làm cho tâm mình trong sạch,",
  "dn14:3.28.9": "đó là lời dạy của chư Phật.",
  "dn14:3.28.10": "Không phỉ báng, không hại người,",
  "dn14:3.28.11": "và giữ gìn theo giới bổn;",
  "dn14:3.28.12": "biết tiết độ trong ăn uống,",
  "dn14:3.28.13": "và chỗ nằm ngồi thanh vắng;",
  "dn14:3.28.14": "siêng năng tu tập tăng thượng tâm,",
  "dn14:3.28.15": "đó là lời dạy của chư Phật.’",
  "dn14:3.29.0": "17. Chư thiên tâu trình",
  "dn14:3.29.1": "Này các Tỳ-kheo, một thời Ta trú tại Ukkaṭṭhā, trong rừng Subhaga, dưới gốc cây chúa sālā.",
  "dn14:3.29.2": "Này các Tỳ-kheo, khi Ta sống viễn ly, an trú độc cư, tâm Ta khởi lên suy nghĩ này:",
  "dn14:3.29.3": "‘Không dễ tìm được một cõi chúng sinh nào mà trong suốt thời gian dài này Ta chưa từng cư trú, ngoại trừ chư thiên ở cõi Tịnh Cư.",
  "dn14:3.29.4": "Hay là Ta đi đến chỗ chư thiên ở cõi Tịnh Cư ấy.’",
  "dn14:3.29.5": "Rồi này các Tỳ-kheo, cũng như một người lực lưỡng co cánh tay lại hay duỗi cánh tay ra; cũng vậy, Ta biến mất tại Ukkaṭṭhā, trong rừng Subhaga, dưới gốc cây chúa sālā, và hiện ra giữa chư thiên ở cõi Avihā.",
  "dn14:3.29.6": "Này các Tỳ-kheo, trong hội chúng chư thiên ấy, nhiều ngàn chư thiên, nhiều trăm ngàn chư thiên đi đến chỗ Ta; đến rồi đảnh lễ Ta và đứng sang một bên. Khi đã đứng sang một bên, này các Tỳ-kheo, các vị chư thiên ấy nói với Ta như sau:",
  "dn14:3.29.7": "‘Này hiền giả, cách đây chín mươi mốt kiếp, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời.",
  "dn14:3.29.8": "Này hiền giả, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc giai cấp Sát-đế-lỵ, sinh trong dòng họ Sát-đế-lỵ.",
  "dn14:3.29.9": "Này hiền giả, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Koṇḍañña.",
  "dn14:3.29.10": "Này hiền giả, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có thọ lượng là tám mươi ngàn năm.",
  "dn14:3.29.11": "Này hiền giả, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã giác ngộ dưới gốc cây pāṭalī.",
  "dn14:3.29.12": "Này hiền giả, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có đôi đệ tử tên là Khaṇḍa và Tissa, là đôi đệ tử tối thắng, tốt lành.",
  "dn14:3.29.13": "Này hiền giả, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có ba hội chúng đệ tử. Một hội chúng đệ tử gồm sáu mươi tám vạn Tỳ-kheo. Một hội chúng đệ tử gồm một trăm ngàn Tỳ-kheo. Một hội chúng đệ tử gồm tám mươi ngàn Tỳ-kheo. Này hiền giả, đó là ba hội chúng đệ tử của đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là các vị lậu tận.",
  "dn14:3.29.14": "Này hiền giả, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có vị thị giả Tỳ-kheo tên là Asoka, là vị thị giả bậc nhất.",
  "dn14:3.29.15": "Này hiền giả, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có phụ thân là vua tên Bandhumā.",
  "dn14:3.29.16": "Mẫu thân, người sinh ra ngài, là hoàng hậu tên Bandhumatī.",
  "dn14:3.29.17": "Kinh đô của vua Bandhuma là thành tên Bandhumatī.",
  "dn14:3.29.18": "Này hiền giả, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã xuất ly như vậy, xuất gia như vậy, tinh tấn như vậy, giác ngộ như vậy, chuyển pháp luân như vậy.",
  "dn14:3.29.19": "Còn chúng tôi, này hiền giả, đã sống phạm hạnh dưới đức Thế Tôn Vipassī, đã làm cho dục tham đối với các dục phai nhạt, nên được sinh về đây.’ …",
  "dn14:3.29.20": "…",
  "dn14:3.30.1": "Ngay trong hội chúng chư thiên ấy, này các Tỳ-kheo, nhiều ngàn chư thiên, nhiều trăm ngàn chư thiên đi đến chỗ Ta; đến rồi đảnh lễ Ta và đứng sang một bên. Khi đã đứng sang một bên, này các Tỳ-kheo, các vị chư thiên ấy nói với Ta như sau:",
  "dn14:3.30.2": "‘Chính trong hiền kiếp này, này hiền giả, đức Thế Tôn hiện nay, bậc A-la-hán, Chánh Đẳng Giác, đã xuất hiện ở đời.",
  "dn14:3.30.3": "Này hiền giả, đức Thế Tôn thuộc giai cấp Sát-đế-lỵ, sinh trong dòng họ Sát-đế-lỵ.",
  "dn14:3.30.4": "Này hiền giả, đức Thế Tôn thuộc họ Gotama.",
  "dn14:3.30.5": "Này hiền giả, thọ lượng của đức Thế Tôn là ít ỏi, ngắn ngủi, nhẹ mỏng; ai sống lâu thì được một trăm năm hoặc hơn chút ít.",
  "dn14:3.30.6": "Này hiền giả, đức Thế Tôn đã giác ngộ dưới gốc cây assattha.",
  "dn14:3.30.7": "Này hiền giả, đức Thế Tôn có đôi đệ tử tên là Sāriputta và Moggallāna, là đôi đệ tử tối thắng, tốt lành.",
  "dn14:3.30.8": "Này hiền giả, đức Thế Tôn có một hội chúng đệ tử gồm một ngàn hai trăm năm mươi Tỳ-kheo. Này hiền giả, đây là một hội chúng đệ tử của đức Thế Tôn, tất cả đều là các vị lậu tận.",
  "dn14:3.30.9": "Này hiền giả, đức Thế Tôn có vị thị giả Tỳ-kheo tên là Ānanda, là vị thị giả bậc nhất.",
  "dn14:3.30.10": "Này hiền giả, đức Thế Tôn có phụ thân là vua tên Suddhodana.",
  "dn14:3.30.11": "Mẫu thân, người sinh ra ngài, là hoàng hậu tên Māyā.",
  "dn14:3.30.12": "Kapilavatthu là tên kinh thành.",
  "dn14:3.30.13": "Này chư hiền, sự xuất ly của Thế Tôn là như vậy, sự xuất gia là như vậy, sự tinh tấn là như vậy, sự giác ngộ viên mãn là như vậy, sự chuyển bánh xe Pháp là như vậy.",
  "dn14:3.30.14": "Này chư hiền, chúng tôi đã sống phạm hạnh dưới bậc Thế Tôn ấy, đã làm cho dục tham đối với các dục phai nhạt, nên được sinh về đây.",
  "dn14:3.31.1": "Rồi này các Tỳ-kheo, Ta cùng với các chư thiên ở cõi Vô Phiền đi đến chỗ các chư thiên Vô Nhiệt…",
  "dn14:3.31.2": "Rồi này các Tỳ-kheo, Ta cùng với các chư thiên ở cõi Vô Phiền và các chư thiên ở cõi Vô Nhiệt đi đến chỗ các chư thiên Thiện Hiện.",
  "dn14:3.31.3": "Rồi này các Tỳ-kheo, Ta cùng với các chư thiên ở cõi Vô Phiền, các chư thiên ở cõi Vô Nhiệt và các chư thiên ở cõi Thiện Hiện đi đến chỗ các chư thiên Thiện Kiến. Rồi này các Tỳ-kheo, Ta cùng với các chư thiên ở cõi Vô Phiền, các chư thiên ở cõi Vô Nhiệt, các chư thiên ở cõi Thiện Hiện và các chư thiên ở cõi Thiện Kiến đi đến chỗ các chư thiên Sắc Cứu Cánh. Này các Tỳ-kheo, tại hội chúng chư thiên ấy, nhiều ngàn thiên tử, nhiều trăm ngàn thiên tử đã đến chỗ Ta; sau khi đến, họ đảnh lễ Ta rồi đứng sang một bên. Đứng sang một bên, này các Tỳ-kheo, các vị chư thiên ấy nói với Ta như sau:",
  "dn14:3.31.4": "‘Này chư hiền, cách đây chín mươi mốt kiếp, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời.",
  "dn14:3.31.5": "Này chư hiền, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng Sát-đế-lỵ.",
  "dn14:3.31.6": "Ngài sinh trong gia tộc Sát-đế-lỵ.",
  "dn14:3.31.7": "Này chư hiền, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Koṇḍañña.",
  "dn14:3.31.8": "Này chư hiền, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có thọ lượng là tám vạn năm.",
  "dn14:3.31.9": "Này chư hiền, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã giác ngộ viên mãn dưới gốc cây pāṭali.",
  "dn14:3.31.10": "Này chư hiền, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có đôi đệ tử là Khaṇḍa và Tissa, là đôi đệ tử tối thắng, tốt lành.",
  "dn14:3.31.11": "Này chư hiền, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có ba hội chúng đệ tử.",
  "dn14:3.31.12": "Một hội chúng đệ tử có sáu trăm tám mươi ngàn Tỳ-kheo.",
  "dn14:3.31.13": "Một hội chúng đệ tử có một trăm ngàn Tỳ-kheo.",
  "dn14:3.31.14": "Một hội chúng đệ tử có tám mươi ngàn Tỳ-kheo.",
  "dn14:3.31.15": "Này chư hiền, ba hội chúng đệ tử ấy của đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đều gồm toàn những vị đã đoạn tận các lậu hoặc.",
  "dn14:3.31.16": "Này chư hiền, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ-kheo thị giả tên là Asoka, là vị thị giả bậc nhất.",
  "dn14:3.31.17": "Này chư hiền, đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có phụ thân là vua Bandhumā, mẫu thân là hoàng hậu Bandhumatī, là người sinh ra Ngài.",
  "dn14:3.31.18": "Kinh thành của vua Bandhumā tên là Bandhumatī.",
  "dn14:3.31.19": "Này chư hiền, sự xuất ly của đức Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác là như vậy, sự xuất gia là như vậy, sự tinh tấn là như vậy, sự giác ngộ viên mãn là như vậy, sự chuyển bánh xe Pháp là như vậy.",
  "dn14:3.31.20": "Này chư hiền, chúng tôi đã sống phạm hạnh dưới đức Thế Tôn Vipassī ấy, đã làm cho dục tham đối với các dục phai nhạt, nên được sinh về đây.’",
  "dn14:3.31.21": "Này các Tỳ-kheo, ngay tại hội chúng chư thiên ấy, nhiều ngàn thiên tử, nhiều trăm ngàn thiên tử đã đến chỗ Ta; sau khi đến, họ đảnh lễ Ta rồi đứng sang một bên. Đứng sang một bên, này các Tỳ-kheo, các vị chư thiên ấy nói với Ta như sau:",
  "dn14:3.31.22": "‘Này chư hiền, cách đây ba mươi mốt kiếp, đức Thế Tôn Sikhī …",
  "dn14:3.31.23": "này chư hiền, chúng tôi dưới đức Thế Tôn Sikhī; cũng chính trong kiếp ba mươi mốt ấy, đức Thế Tôn Vessabhū …",
  "dn14:3.31.24": "này chư hiền, chúng tôi dưới đức Thế Tôn Vessabhū …",
  "dn14:3.31.25": "ngay trong hiền kiếp này, các đức Thế Tôn Kakusandha, Koṇāgamana, Kassapa …",
  "dn14:3.31.26": "này chư hiền, chúng tôi đã sống phạm hạnh dưới các đức Thế Tôn Kakusandha, Koṇāgamana và Kassapa, đã làm cho dục tham đối với các dục phai nhạt, nên được sinh về đây.’",
  "dn14:3.32.1": "Này các Tỳ-kheo, ngay tại hội chúng chư thiên ấy, nhiều ngàn thiên tử, nhiều trăm ngàn thiên tử đã đến chỗ Ta; sau khi đến, họ đảnh lễ Ta rồi đứng sang một bên. Đứng sang một bên, này các Tỳ-kheo, các vị chư thiên ấy nói với Ta như sau:",
  "dn14:3.32.2": "‘Này chư hiền, ngay trong hiền kiếp này, hiện nay đức Thế Tôn, bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời.",
  "dn14:3.32.3": "Này chư hiền, đức Thế Tôn thuộc dòng Sát-đế-lỵ, sinh trong gia tộc Sát-đế-lỵ.",
  "dn14:3.32.4": "Này chư hiền, đức Thế Tôn thuộc họ Gotama.",
  "dn14:3.32.5": "Này chư hiền, thọ lượng của đức Thế Tôn là ít ỏi, ngắn ngủi, nhẹ mỏng; ai sống lâu thì được một trăm năm hoặc hơn chút ít.",
  "dn14:3.32.6": "Này chư hiền, đức Thế Tôn đã giác ngộ viên mãn dưới gốc cây assattha.",
  "dn14:3.32.7": "Này chư hiền, đức Thế Tôn có đôi đệ tử là Sāriputta và Moggallāna, là đôi đệ tử tối thắng, tốt lành.",
  "dn14:3.32.8": "Này chư hiền, đức Thế Tôn có một hội chúng đệ tử gồm một ngàn hai trăm năm mươi Tỳ-kheo.",
  "dn14:3.32.9": "Này chư hiền, hội chúng đệ tử này của đức Thế Tôn đều gồm toàn những vị đã đoạn tận các lậu hoặc.",
  "dn14:3.32.10": "Này chư hiền, đức Thế Tôn có vị Tỳ-kheo thị giả tên là Ānanda, là vị thị giả bậc nhất.",
  "dn14:3.32.11": "Này chư hiền, phụ thân của đức Thế Tôn là vua Suddhodana.",
  "dn14:3.32.12": "Mẫu thân là hoàng hậu Māyā, là người sinh ra Ngài.",
  "dn14:3.32.13": "Kapilavatthu là tên kinh thành.",
  "dn14:3.32.14": "Này chư hiền, sự xuất ly của đức Thế Tôn là như vậy, sự xuất gia là như vậy, sự tinh tấn là như vậy, sự giác ngộ viên mãn là như vậy, sự chuyển bánh xe Pháp là như vậy.",
  "dn14:3.32.15": "Này chư hiền, chúng tôi đã sống phạm hạnh dưới bậc Thế Tôn ấy, đã làm cho dục tham đối với các dục phai nhạt, nên được sinh về đây.’",
  "dn14:3.33.1": "Này các Tỳ-kheo, chính vì vậy mà giới pháp của Như Lai đã được thấu triệt khéo léo; do giới pháp ấy được thấu triệt khéo léo, Như Lai nhớ lại được các đức Phật quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận diệt vòng quay, đã vượt qua mọi khổ đau, nhớ lại cả về dòng sinh, nhớ lại cả về tên gọi, nhớ lại cả về họ tộc, nhớ lại cả về thọ lượng, nhớ lại cả về đôi đệ tử, nhớ lại cả về các hội chúng đệ tử rằng: ‘Các đức Thế Tôn ấy có sự sinh ra như vậy.’",
  "dn14:3.33.2": "‘Các đức Thế Tôn ấy có tên như vậy, họ như vậy, giới như vậy, pháp như vậy, tuệ như vậy, an trú như vậy, giải thoát như vậy.’",
  "dn14:3.33.3": "Chư thiên cũng đã trình bày ý nghĩa ấy với Như Lai, nhờ đó Như Lai nhớ lại được các đức Phật quá khứ đã nhập Niết-bàn, đã dứt mọi hý luận, đã chặt đứt đường luân hồi, đã tận diệt vòng quay, đã vượt qua mọi khổ đau, nhớ lại cả về dòng sinh, nhớ lại cả về tên gọi, nhớ lại cả về họ tộc, nhớ lại cả về thọ lượng, nhớ lại cả về đôi đệ tử, nhớ lại cả về các hội chúng đệ tử rằng: ‘Các đức Thế Tôn ấy có sự sinh ra như vậy.’",
  "dn14:3.33.4": "‘Các đức Thế Tôn ấy có tên như vậy, họ như vậy, giới như vậy, pháp như vậy, tuệ như vậy, an trú như vậy, giải thoát như vậy.’",
  "dn14:3.33.5": "Thế Tôn đã nói như vậy.",
  "dn14:3.33.6": "Các Tỳ-kheo hoan hỷ tín thọ lời Thế Tôn dạy.",
  "dn14:3.33.7": "Kinh Đại Bổn thứ nhất đến đây chấm dứt."
}
window.BILARA["dn14"]["vi"]["dn14:source"] =
  "Dịch từ nguồn Pali https://suttacentral.net/";
